/* Spellbound — concept EXPLANATION scripts (authored from concept data; the bee narrates).
   show types: glyph{text,sub} word{word,hi} list{items} breakdown{word,hi,parts:[{txt,gloss}]} build{...} */
window.SB_CSCRIPT = {"0":{"label":"Latin ego / Greek auto","scenes":[{"mood":"happy","cap":"ego = Latin “I”","say":"Meet the root ego, spelled E, G, O. It comes from Latin and it simply means I. So these words are all about how a person feels about themselves.","show":{"t":"glyph","text":"ego","sub":"Latin: I"}},{"mood":"oops","cap":"egoist vs egotist — the extra t = talk","say":"Here's a tricky pair. An egoist cares only about themselves. An egotist constantly talks about themselves, and that extra t stands for talking. Same root, just a different suffix.","show":{"t":"list","items":[{"word":"egoist","hi":[0,3]},{"word":"egotist","hi":[0,3]}]}},{"mood":"happy","cap":"ego + mania (madness) → egomaniac","say":"Build ego up bigger. Ego plus the Greek mania, meaning madness, gives egomaniac, someone whose self-obsession has gone to an extreme.","show":{"t":"breakdown","word":"egomaniac","hi":[0,3],"parts":[{"txt":"ego","gloss":"I, self"},{"txt":"mania","gloss":"madness"}]}},{"mood":"excited","cap":"auto- = self (by oneself)","say":"Now the Greek side. Auto, spelled A, U, T, O, means self. An autodidact is auto plus didaskein, meaning to teach, so a person who is self-taught.","show":{"t":"breakdown","word":"autodidact","hi":[0,4],"parts":[{"txt":"auto","gloss":"self"},{"txt":"didaskein","gloss":"to teach"}]}},{"mood":"excited","cap":"ego = I · auto = self","say":"So whenever you spot E, G, O, think I, and when you spot A, U, T, O, think self. A whole family of personality words opens right up.","show":{"t":"list","items":[{"word":"egocentric","hi":[0,3]},{"word":"autonomous","hi":[0,4]}]}}]},"1":{"label":"Latin loqu · Greek phon","scenes":[{"mood":"happy","cap":"loqu = to speak","say":"Meet the root loqu, spelled L, O, Q, U. It comes from Latin and means to speak. It hides inside loads of words about talking.","show":{"t":"glyph","text":"loqu","sub":"Latin: to speak"}},{"mood":"happy","cap":"ventri (belly) + loqu (speak) → ventriloquist","say":"Take ventriloquist. Ventri means belly, and loqu means speak. So a ventriloquist seems to speak from the belly, while their lips stay still.","show":{"t":"breakdown","word":"ventriloquist","hi":[7,4],"parts":[{"txt":"ventri","gloss":"belly"},{"txt":"loqu","gloss":"speak"}]}},{"mood":"happy","cap":"solo + loquy → soliloquy","say":"Or soliloquy. Solo means alone, plus loquy from speak, so it's a speech where someone on stage talks all alone to themselves.","show":{"t":"breakdown","word":"soliloquy","hi":[4,5],"parts":[{"txt":"soli","gloss":"alone"},{"txt":"loquy","gloss":"speech"}]}},{"mood":"oops","cap":"phon = sound — always ph, never f!","say":"Switch to Greek. Phon, spelled P, H, O, N, means sound or voice. Watch out, it's always spelled p h, never f. That p h is the Greek signal.","show":{"t":"glyph","text":"phon","sub":"Greek: sound (ph!)"}},{"mood":"excited","cap":"sym (together) + phon (sound) → symphony","say":"So symphony is sym, together, plus phon, sound, sounds blending together. Spot L, O, Q, U for speaking and p h o n for sound, and these words decode instantly.","show":{"t":"breakdown","word":"symphony","hi":[3,4],"parts":[{"txt":"sym","gloss":"together"},{"txt":"phon","gloss":"sound"}]}}]},"2":{"label":"Latin ver · pseudo","scenes":[{"mood":"happy","cap":"ver = truth","say":"Meet the root ver, spelled V, E, R. It comes from the Latin veritas, meaning truth. It shows up wherever something is true.","show":{"t":"glyph","text":"ver","sub":"Latin: truth"}},{"mood":"happy","cap":"ver (truth) + dict (say) → verdict","say":"Take verdict. Ver means truth, plus dict, meaning say. A verdict is what a jury truly states after weighing the facts.","show":{"t":"breakdown","word":"verdict","hi":[0,3],"parts":[{"txt":"ver","gloss":"truth"},{"txt":"dict","gloss":"say"}]}},{"mood":"oops","cap":"veracious ≠ voracious!","say":"Careful with a famous trap. Veracious, with an e, means truthful. But voracious, with an o, means greedy. One tiny vowel flips the whole meaning.","show":{"t":"list","items":[{"word":"veracious","hi":[0,3]},{"word":"veracity","hi":[0,3]}]}},{"mood":"happy","cap":"mendax = lying — a mendacious person mends the truth","say":"The opposite root is mendax, meaning lying. Mendacious means habitually untruthful. A memory trick: a mendacious person mends, or bends, the truth.","show":{"t":"breakdown","word":"mendacious","hi":[0,4],"parts":[{"txt":"mendax","gloss":"lying"}]}},{"mood":"excited","cap":"pseudo- = false · SILENT p! P-S-E-U-D-O","say":"Last, the Greek pseudo means false, but here's the trap. It begins with a silent p. You spell it P, S, E, U, D, O, but you say soo-doh.","show":{"t":"glyph","text":"pseudo","sub":"false (silent p!)"}}]},"3":{"label":"The Four Humors","scenes":[{"mood":"love","cap":"4 fluids → 4 emotion words","say":"Here's a delightful old idea. Doctors once believed four body fluids shaped your mood, and that gave English four emotion words we still use today.","show":{"t":"list","items":[{"word":"sanguine"},{"word":"choleric"},{"word":"melancholy"}]}},{"mood":"happy","cap":"sanguis (blood) → sanguine, optimistic","say":"Blood was thought to bring joy. Sanguine comes from the Latin sanguis, meaning blood, and it means cheerful and optimistic. Watch the silent e on the end.","show":{"t":"breakdown","word":"sanguine","hi":[0,7],"parts":[{"txt":"sanguis","gloss":"blood"}]}},{"mood":"happy","cap":"khole (bile) → choleric · ch = /k/","say":"Yellow bile brought anger. Choleric comes from the Greek khole, meaning bile, and means quick-tempered. The c h here sounds like a k, a Greek signal.","show":{"t":"breakdown","word":"choleric","hi":[0,2],"parts":[{"txt":"khole","gloss":"bile"}]}},{"mood":"oops","cap":"phlegmatic — silent g! P-H-L-E-G-M","say":"Now the hardest one. Phlegmatic, from the Greek phlegma, means so calm it seems indifferent. It has two traps at once, the p h, and a silent g. Spell P, H, L, E, G, M.","show":{"t":"glyph","text":"phlegm","sub":"ph + silent g"}},{"mood":"excited","cap":"blood · bile · phlegm · black bile","say":"So four old fluids gave us sanguine, choleric, phlegmatic, and melancholy. Remember the ph and the silent letters, and these tricky words are yours.","show":{"t":"list","items":[{"word":"phlegmatic","hi":[0,2]},{"word":"melancholy"}]}}]},"4":{"label":"Latin sap · Greek sophos","scenes":[{"mood":"happy","cap":"sap = wise","say":"Meet the root sap, spelled S, A, P. It comes from the Latin sapientia, meaning wisdom. Sapient means genuinely wise.","show":{"t":"glyph","text":"sap","sub":"Latin: wise"}},{"mood":"excited","cap":"-acious → -acity: drop -ious, add -ity","say":"Here's a locked-in pattern. Adjectives ending in a c i o u s become nouns ending in a c i t y. Sagacious becomes sagacity. Just drop i o u s, and add i t y.","show":{"t":"list","items":[{"word":"sagacious","hi":[3,6]},{"word":"sagacity","hi":[3,5]}]}},{"mood":"love","cap":"sophos (wise) + moros (fool) → sophomore","say":"Now the Greek sophos, meaning wise. My favorite is sophomore. Sophos, wise, plus moros, meaning fool, so a wise fool, a second-year student who thinks they know it all.","show":{"t":"breakdown","word":"sophomore","hi":[0,4],"parts":[{"txt":"soph","gloss":"wise"},{"txt":"moros","gloss":"fool"}]}},{"mood":"happy","cap":"philos (love) + sophia (wisdom) → philosophy","say":"Sophos shows up again in philosophy. Philos means love, plus sophia, wisdom, so philosophy is literally the love of wisdom.","show":{"t":"breakdown","word":"philosophy","hi":[4,4],"parts":[{"txt":"philos","gloss":"love"},{"txt":"sophia","gloss":"wisdom"}]}},{"mood":"excited","cap":"sap & soph both = wise","say":"So spot S, A, P or s o p h, and think wise. And remember the pattern: an a c i o u s adjective always has an a c i t y noun waiting.","show":{"t":"glyph","text":"sap · soph","sub":"wise"}}]},"5":{"label":"Latin aud · fort · tim","scenes":[{"mood":"happy","cap":"aud = to dare","say":"Meet the root aud, spelled A, U, D. It comes from the Latin audere, meaning to dare. Audacious means daringly bold.","show":{"t":"glyph","text":"aud","sub":"Latin: to dare"}},{"mood":"oops","cap":"audacious (dare) ≠ audible (hear)","say":"Watch this trap. Audacious, meaning daring, shares a u d with audible, meaning able to be heard, from audire. Same letters, two different roots. The meaning tells you which.","show":{"t":"list","items":[{"word":"audacious","hi":[0,3]},{"word":"audible","hi":[0,3]}]}},{"mood":"happy","cap":"ex + fort (strong) → effort","say":"Next, fort, spelled F, O, R, T, from the Latin fortis, meaning strong. Effort is ex, meaning out, plus fort, so it's strength pushed outward.","show":{"t":"breakdown","word":"fortitude","hi":[0,4],"parts":[{"txt":"fort","gloss":"strong"}]}},{"mood":"happy","cap":"in + timid → intimidate (put fear in)","say":"Then tim, from the Latin timor, meaning fear. Timid means easily frightened, and to intimidate is to put fear into someone.","show":{"t":"breakdown","word":"intimidate","hi":[2,5],"parts":[{"txt":"in","gloss":"into"},{"txt":"tim","gloss":"fear"}]}},{"mood":"oops","cap":"temerity = reckless boldness, NOT timidity","say":"One last trick. Temerity sounds like timid but it's the opposite. From temere, meaning recklessly, it means reckless boldness. A classic bee trap.","show":{"t":"glyph","text":"temerity","sub":"reckless boldness"}}]},"6":{"label":"Latin ben · mal","scenes":[{"mood":"happy","cap":"bene = well / good","say":"Meet the root bene, spelled B, E, N, E. It comes from Latin and means well, or good. It marks the kind, generous words.","show":{"t":"glyph","text":"bene","sub":"Latin: well, good"}},{"mood":"happy","cap":"bene (well) + velle (wish) → benevolent","say":"Take benevolent. Bene means well, plus velle, meaning to wish. So a benevolent person wishes good for others.","show":{"t":"breakdown","word":"benevolent","hi":[0,4],"parts":[{"txt":"bene","gloss":"well"},{"txt":"velle","gloss":"to wish"}]}},{"mood":"happy","cap":"mal = bad / evil","say":"Now its opposite. Mal, spelled M, A, L, comes from the Latin malus, meaning bad. It paints everything it touches as bad.","show":{"t":"glyph","text":"mal","sub":"Latin: bad, evil"}},{"mood":"excited","cap":"swap ben for mal → meaning flips!","say":"Here's the magic. Swap bene for mal and the meaning flips. Benevolent wishes good, malevolent wishes harm. Know one word of the pair, and you know both.","show":{"t":"list","items":[{"word":"benevolent","hi":[0,4]},{"word":"malevolent","hi":[0,3]}]}},{"mood":"love","cap":"mal- + Italian aria (air) → malaria","say":"And etymology can be history. Malaria is mal, bad, plus the Italian aria, meaning air. Italians once blamed the disease on bad swamp air, before anyone knew about mosquitoes.","show":{"t":"breakdown","word":"malaria","hi":[0,3],"parts":[{"txt":"mal","gloss":"bad"},{"txt":"aria","gloss":"air"}]}}]},"7":{"label":"Latin greg · Greek mis","scenes":[{"mood":"happy","cap":"greg = flock","say":"Meet the root greg, spelled G, R, E, G. It comes from the Latin grex, meaning flock, a group of animals. Gregarious means loving to be in a group.","show":{"t":"glyph","text":"greg","sub":"Latin: flock"}},{"mood":"oops","cap":"e- (out of) + greg → egregious = outstandingly BAD","say":"Here's a sneaky one. Egregious is e, meaning out of, plus greg, the flock. So it stands out from the flock, but in an outstandingly bad way.","show":{"t":"breakdown","word":"egregious","hi":[1,4],"parts":[{"txt":"e","gloss":"out of"},{"txt":"greg","gloss":"flock"}]}},{"mood":"happy","cap":"anthropos = human being","say":"Now the Greek anthropos, meaning human being. Anthropology, spelled with that root, is simply the study of humans.","show":{"t":"breakdown","word":"anthropology","hi":[0,7],"parts":[{"txt":"anthropos","gloss":"human"},{"txt":"logy","gloss":"study of"}]}},{"mood":"excited","cap":"mis (hate) + anthropos (human) → misanthrope","say":"Add the Greek misos, meaning hatred. A misanthrope is misos, hate, plus anthropos, human, someone who hates people in general.","show":{"t":"breakdown","word":"misanthrope","hi":[0,3],"parts":[{"txt":"mis","gloss":"hatred"},{"txt":"anthrope","gloss":"human"}]}},{"mood":"oops","cap":"Greek mis- (hate) ≠ Latin mis- (wrongly)","say":"But careful. This mis is Greek and means hatred, totally different from the Latin mis that means wrongly, as in mistake. Same spelling, completely different origin.","show":{"t":"glyph","text":"mis-","sub":"Greek: hatred"}}]},"8":{"label":"Latin in- (not)","scenes":[{"mood":"happy","cap":"in- = not","say":"Meet the prefix in, spelled I, N. It comes from Latin and means not. Insane means not sane. Simple enough, but it has a clever trick.","show":{"t":"glyph","text":"in-","sub":"Latin: not"}},{"mood":"excited","cap":"in- assimilates: il- · im- · ir-","say":"Here's the clever part. In changes shape to match the next letter. Before l it becomes il, before m, b, or p it becomes im, and before r it becomes ir.","show":{"t":"glyph","text":"in → il, im, ir","sub":"one prefix, four shapes"}},{"mood":"happy","cap":"im- + pecca (sin) → impeccable","say":"Take impeccable. The prefix turned into im, plus pecca, meaning sin. So impeccable means without a single fault, flawless.","show":{"t":"breakdown","word":"impeccable","hi":[0,2],"parts":[{"txt":"im","gloss":"not"},{"txt":"pecca","gloss":"sin"}]}},{"mood":"happy","cap":"in- + amicus (friend) → inimical","say":"Or inimical. In, not, plus amicus, meaning friend. So inimical means not friendly, hostile.","show":{"t":"breakdown","word":"inimical","hi":[0,2],"parts":[{"txt":"in","gloss":"not"},{"txt":"amicus","gloss":"friend"}]}},{"mood":"oops","cap":"the doubled letter reveals the hidden prefix","say":"So here's your spelling key. The doubled letter, the two l's, two r's, or m next to a b, is the prefix meeting the root. Spot the doubling, and you spot the hidden not.","show":{"t":"list","items":[{"word":"irregular","hi":[0,2]},{"word":"illegible","hi":[0,2]}]}}]},"9":{"label":"un- (not / reverse)","scenes":[{"mood":"happy","cap":"un- = not OR reverse","say":"Meet the prefix un, spelled U, N. It has two jobs. Before an adjective it means not, and before a verb it means reverse the action.","show":{"t":"glyph","text":"un-","sub":"not / reverse"}},{"mood":"happy","cap":"un- + adjective = not","say":"Before an adjective, un means not. Unkempt is un plus kempt, an old word for combed, so unkempt means not combed, messy.","show":{"t":"breakdown","word":"unkempt","hi":[0,2],"parts":[{"txt":"un","gloss":"not"},{"txt":"kempt","gloss":"combed"}]}},{"mood":"happy","cap":"un- + verb = reverse the action","say":"Before a verb, un reverses things. Undo, unwrap, unravel, each one undoes the action. The word's job tells you which meaning of un you've got.","show":{"t":"list","items":[{"word":"undo","hi":[0,2]},{"word":"unravel","hi":[0,2]}]}},{"mood":"oops","cap":"un- + n-root → double n! U-N-N","say":"Watch this spelling trap. When un meets a root that starts with n, you get a double n. Unnecessary is U, N, N. The first n is the prefix, the second begins the root.","show":{"t":"breakdown","word":"unnecessary","hi":[0,2],"parts":[{"txt":"un","gloss":"not"},{"txt":"necessary","gloss":"needed"}]}},{"mood":"excited","cap":"un- = Old English · in- = Latin","say":"One more thing. Un is Old English, while in is Latin. So Germanic words take un, like unhappy, and Latin words often take in. Spot the double n, and you'll spell it right.","show":{"t":"list","items":[{"word":"unnatural","hi":[0,2]},{"word":"unnerve","hi":[0,2]}]}}]},"10":{"label":"dis- (apart / not)","scenes":[{"mood":"happy","cap":"dis- = apart / not","say":"Meet the prefix dis, spelled D, I, S. It comes from Latin and means apart, not, or deprived of. It pulls things in two.","show":{"t":"glyph","text":"dis-","sub":"apart / not"}},{"mood":"oops","cap":"dis- + s-root → double s! diss-","say":"Here's the key spelling trap. When dis meets a root that starts with s, you get a double s. Dissipate, dissolve, dissent, all spelled d i s s.","show":{"t":"list","items":[{"word":"dissipate","hi":[0,4]},{"word":"dissolve","hi":[0,4]}]}},{"mood":"happy","cap":"dis- + semen (seed) → disseminate","say":"Take disseminate. Dis, meaning apart, plus semen, meaning seed. So to disseminate is to scatter seeds of an idea apart, far and wide. And yes, double s.","show":{"t":"breakdown","word":"disseminate","hi":[0,4],"parts":[{"txt":"dis","gloss":"apart"},{"txt":"semen","gloss":"seed"}]}},{"mood":"happy","cap":"dis- + sonus (sound) → dissonance","say":"Or dissonance. Dis, apart, plus sonus, meaning sound. Sounds pulling apart from each other, a harsh clash. Again, that double s.","show":{"t":"breakdown","word":"dissonance","hi":[0,4],"parts":[{"txt":"dis","gloss":"apart"},{"txt":"sonus","gloss":"sound"}]}},{"mood":"oops","cap":"discomfit ≠ discomfort","say":"Last, a meaning trap. Discomfit does not mean discomfort. Discomfit means to defeat or thwart someone, not just to make them a little uncomfortable.","show":{"t":"glyph","text":"discomfit","sub":"to defeat"}}]},"11":{"label":"Latin de- (down/away)","scenes":[{"mood":"happy","cap":"de- = down / away / reverse","say":"Meet the prefix de, spelled D, E. It comes from Latin. It can remove, reverse, go down, or even mean thoroughly. And it never changes shape.","show":{"t":"glyph","text":"de-","sub":"down / away / reverse"}},{"mood":"happy","cap":"de- + siccus (dry) → desiccate","say":"Take desiccate. De plus the Latin siccus, meaning dry. So to desiccate is to remove all the moisture and dry something out completely.","show":{"t":"breakdown","word":"desiccate","hi":[0,2],"parts":[{"txt":"de","gloss":"remove"},{"txt":"siccus","gloss":"dry"}]}},{"mood":"love","cap":"de- + decimus (tenth) → decimate","say":"Here's a vivid one. Decimate is de plus decimus, meaning tenth. It originally meant to kill one Roman soldier in every ten as punishment. Now it means to destroy a large part.","show":{"t":"breakdown","word":"decimate","hi":[0,2],"parts":[{"txt":"de","gloss":"down"},{"txt":"decimus","gloss":"tenth"}]}},{"mood":"oops","cap":"desiccate = D-E-S-I-C-C-A-T-E (double c)","say":"Watch the spelling of desiccate. It has one s but a double c, from the Latin siccare. Spell it D, E, S, I, C, C, A, T, E.","show":{"t":"glyph","text":"desiccate","sub":"one s, double c"}},{"mood":"excited","cap":"de- removes · dis- separates","say":"And don't mix de with dis. De means reversal or removal, like decode. Dis means separation or absence, like disagree. Direction versus absence, that's the difference.","show":{"t":"list","items":[{"word":"decode","hi":[0,2]},{"word":"disagree","hi":[0,3]}]}}]},"12":{"label":"Latin ex-","scenes":[{"mood":"happy","show":{"t":"glyph","text":"ex-","sub":"out of"},"cap":"ex- comes from Latin and means “out of.”","say":"Let's meet the prefix ex, spelled E X. It comes from Latin, and it means out of."},{"mood":"excited","show":{"t":"glyph","text":"ex → ef → e","sub":"one prefix, three shapes"},"cap":"It changes shape to match the next letter.","say":"Here's the clever part. Ex changes its shape to match the letter that follows it. Before an f, it turns into ef."},{"mood":"happy","show":{"t":"breakdown","word":"effervescent","hi":[0,2],"parts":[{"txt":"ef-","gloss":"out (from ex-)"},{"txt":"fervere","gloss":"to boil"}]},"cap":"ef- + fervere (boil) → effervescent","say":"So ef, plus the Latin fervere, meaning to boil, gives us effervescent — something boiling out, and bubbling over."},{"mood":"happy","show":{"t":"glyph","text":"e-","sub":"the x drops"},"cap":"Before many consonants, the x just drops.","say":"And before many consonants, the x simply drops away, leaving just e — as in elect, and emit."},{"mood":"excited","show":{"t":"glyph","text":"ex- ef- e-","sub":"spot the hidden “out”"},"cap":"Same prefix, three shapes — spot the hidden “out.”","say":"Same prefix, three shapes — ex, ef, and e. Spot the hidden out of, and you'll spell every one of them right."}]},"13":{"label":"Latin re- (again/back)","scenes":[{"mood":"happy","cap":"re- = again / back","say":"Meet the prefix re, spelled R, E. It comes from Latin and means again, or back. It's one of the most common prefixes in English.","show":{"t":"glyph","text":"re-","sub":"again / back"}},{"mood":"happy","cap":"re- + naissance (birth) → renaissance","say":"Take renaissance. Re, meaning again, plus naissance, meaning birth. So a renaissance is a rebirth, a fresh blooming of art and learning.","show":{"t":"breakdown","word":"renaissance","hi":[0,2],"parts":[{"txt":"re","gloss":"again"},{"txt":"naissance","gloss":"birth"}]}},{"mood":"happy","cap":"re- + trahere (drag) → retract","say":"Or retract. Re, meaning back, plus trahere, meaning to drag. So to retract is to drag a statement back, to withdraw it.","show":{"t":"breakdown","word":"retract","hi":[0,2],"parts":[{"txt":"re","gloss":"back"},{"txt":"trahere","gloss":"to drag"}]}},{"mood":"oops","cap":"Sometimes re- is NOT a prefix!","say":"Here's a trap. Not every re is a prefix. In reticent, from reticere meaning be silent, the re is part of the root. Take it off and ticent isn't a word.","show":{"t":"glyph","text":"reticent","sub":"re- is part of the root"}},{"mood":"excited","cap":"the test: remove re-, is the rest a word?","say":"So here's your test. Take off the re. If what's left is a real word, re was a prefix. If not, re belongs to the root. That trick unlocks dozens of words.","show":{"t":"list","items":[{"word":"redo","hi":[0,2]},{"word":"return","hi":[0,2]}]}}]},"14":{"label":"Latin pre- / pro-","scenes":[{"mood":"happy","cap":"pre- = before · pro- = forward","say":"Let's meet two cousins. Pre, spelled P R E, means before in time or place. Pro, spelled P R O, means forward, or in favor of.","show":{"t":"glyph","text":"pre- · pro-","sub":"before · forward"}},{"mood":"happy","cap":"precocious = pre- + coquere (cook)","say":"Take precocious. Pre, before, plus the Latin coquere, to cook. Something cooked before its time, so a precocious kid is unusually grown up early.","show":{"t":"breakdown","word":"precocious","hi":[0,3],"parts":[{"txt":"pre-","gloss":"before"},{"txt":"coquere","gloss":"to cook"}]}},{"mood":"happy","cap":"provenance = pro- + venire (come)","say":"Now pro. Take provenance. Pro, forward, plus the Latin venire, to come. It means where something came from, its origin.","show":{"t":"breakdown","word":"provenance","hi":[0,3],"parts":[{"txt":"pro-","gloss":"forward"},{"txt":"venire","gloss":"to come"}]}},{"mood":"oops","cap":"prescribe vs proscribe — opposite!","say":"Watch this trap. Prescribe, pre plus scribere, to write, means a doctor writes you a remedy. But proscribe, with pro, means to forbid. Same sound, opposite directions.","show":{"t":"list","items":[{"word":"prescribe","hi":[0,3]},{"word":"proscribe","hi":[0,3]}]}},{"mood":"excited","cap":"See pre- = before, pro- = forward","say":"So whenever you hear that prefix, ask which way it points. Pre looks back to before, and pro pushes forward. Get the direction right and you'll spell them right.","show":{"t":"glyph","text":"pre- · pro-","sub":"before vs forward"}}]},"15":{"label":"Latin sub- / super-","scenes":[{"mood":"happy","cap":"sub- = under, super- = above","say":"Meet two opposites. Sub, spelled S U B, means under. And super, spelled S U P E R, means above or beyond.","show":{"t":"glyph","text":"sub- · super-","sub":"under · above"}},{"mood":"happy","cap":"sub- hides as sur-, suf-, sug-, sup-","say":"Here's the clever part. Sub changes shape to match the next letter. Before r it becomes sur, before f it becomes suf, before g sug, and before p sup. That doubled letter is the hidden sub.","show":{"t":"glyph","text":"sub → sur/suf/sug/sup","sub":"the doubled letter is sub-"}},{"mood":"happy","cap":"subterfuge = sub- + fuga (flight)","say":"Take subterfuge. Sub, under, plus the Latin fuga, flight. A flight taken under cover, which is a sneaky, deceptive trick.","show":{"t":"breakdown","word":"subterfuge","hi":[0,3],"parts":[{"txt":"sub-","gloss":"under"},{"txt":"fuga","gloss":"flight"}]}},{"mood":"oops","cap":"supersede — -sede, NOT -cede!","say":"Now a famous trap. Supersede, super plus sedere, to sit, means to sit above and replace. It ends S E D E, not C E D E. It's the only common word that does.","show":{"t":"word","word":"supersede","hi":[5,4]}},{"mood":"excited","cap":"Spot the doubled letter — find sub-","say":"So spot the doubled letter and you've found the hidden under. Surreptitious has a double r, suffice a double f. The spelling tells you the prefix.","show":{"t":"word","word":"surreptitious","hi":[0,3]}}]},"16":{"label":"Latin com- / con-","scenes":[{"mood":"happy","cap":"com- = with, together","say":"Meet the prefix com, spelled C O M. It comes from Latin and it means with, or together.","show":{"t":"glyph","text":"com-","sub":"with · together"}},{"mood":"happy","cap":"com- → col-, cor-, con-","say":"Like its cousins, com changes shape to match the root. Before l it becomes col, before r it becomes cor, and before most other letters it becomes con. The doubled letter signals it.","show":{"t":"glyph","text":"com → col/cor/con","sub":"matches the next letter"}},{"mood":"happy","cap":"corroborate = cor- + robur (strength)","say":"Take corroborate. Cor, together, plus the Latin robur, strength. To strengthen together, which means to confirm the evidence. That double r is the prefix meeting the root.","show":{"t":"breakdown","word":"corroborate","hi":[0,3],"parts":[{"txt":"cor-","gloss":"together"},{"txt":"robur","gloss":"strength"}]}},{"mood":"oops","cap":"complacent ≠ complaisant","say":"Watch this pair. Complacent, from placere, to please, means smugly pleased with yourself. But complaisant means eager to please others. One smug, one obliging.","show":{"t":"list","items":[{"word":"complacent"},{"word":"complaisant"}]}},{"mood":"excited","cap":"Double letter = the with hiding inside","say":"So whenever you see that doubled letter, think with, or together. Collaborate, correlate, connoisseur. The spelling quietly tells you the origin.","show":{"t":"word","word":"collaborate","hi":[0,3]}}]},"17":{"label":"Latin mal-","scenes":[{"mood":"happy","cap":"mal- from Latin malus = bad","say":"Meet the prefix mal, spelled M A L. It comes from the Latin malus, meaning bad or evil. It's a reliable warning sign.","show":{"t":"glyph","text":"mal-","sub":"bad · evil · ill"}},{"mood":"happy","cap":"malevolent = mal- + velle (wish)","say":"Take malevolent. Mal, evil, plus the Latin velle, to wish. A malevolent person wishes evil on others. Every mal word carries that Latin warning.","show":{"t":"breakdown","word":"malevolent","hi":[0,3],"parts":[{"txt":"mal-","gloss":"evil"},{"txt":"velle","gloss":"to wish"}]}},{"mood":"love","cap":"malaria = mal- + Italian aria (air)","say":"Here's a lovely bit of history. Malaria is mal plus the Italian aria, air. Bad air. People blamed swampy air for the fever before anyone knew about mosquitoes.","show":{"t":"breakdown","word":"malaria","hi":[0,3],"parts":[{"txt":"mal-","gloss":"bad"},{"txt":"aria","gloss":"air"}]}},{"mood":"happy","cap":"mal- ↔ ben-: opposites in pairs","say":"Every mal word has a good twin. Malevolent flips to benevolent, malediction to benediction. Know one side and you know both.","show":{"t":"list","items":[{"word":"malevolent","hi":[0,3]},{"word":"malediction","hi":[0,3]}]}},{"mood":"excited","cap":"mal- never changes — always M-A-L","say":"And the best news for spelling. Unlike its cousins, mal never changes shape. It is always M A L. See those three letters, think bad, and spell it with confidence.","show":{"t":"glyph","text":"M-A-L","sub":"always the same"}}]},"18":{"label":"mis- (wrongly)","scenes":[{"mood":"happy","cap":"mis- = wrongly, badly, astray","say":"Meet the prefix mis, spelled M I S. It means done wrongly, badly, or astray.","show":{"t":"glyph","text":"mis-","sub":"wrongly · badly"}},{"mood":"happy","cap":"misnomer = mis- + nomen (name)","say":"Take misnomer. Mis, wrongly, plus the Latin nomen, name. A misnomer is a name that's wrongly applied to something.","show":{"t":"breakdown","word":"misnomer","hi":[0,3],"parts":[{"txt":"mis-","gloss":"wrongly"},{"txt":"nomen","gloss":"name"}]}},{"mood":"oops","cap":"misspell = mis- + spell → double s","say":"Now a sneaky one. Misspell has a double s. That's just mis meeting a root that starts with s, spell. Same with misstep and misstate. Not a doubling rule, just two s's bumping together.","show":{"t":"word","word":"misspell","hi":[2,2]}},{"mood":"oops","cap":"misanthrope is Greek, not this mis-","say":"Careful here. Misanthrope starts with the same letters but comes from the Greek misos, hatred. It means someone who dislikes people. A completely different root.","show":{"t":"word","word":"misanthrope","hi":[0,3]}},{"mood":"excited","cap":"Test: drop mis-, is the rest a word?","say":"Here's your test. Take off mis. If what's left is a real word, like guide in misguide, then mis is the prefix and it means wrongly. Simple and reliable.","show":{"t":"glyph","text":"mis- + word","sub":"drop it and check"}}]},"19":{"label":"inter- / intra-","scenes":[{"mood":"happy","cap":"inter- = between, intra- = within","say":"Two prefixes, one letter apart. Inter, spelled I N T E R, means between two things. Intra, spelled I N T R A, means inside one thing.","show":{"t":"glyph","text":"inter- · intra-","sub":"between · within"}},{"mood":"happy","cap":"international vs intramural","say":"Hear the difference. International means between nations. But intramural means within the walls of one school. One letter changes everything.","show":{"t":"list","items":[{"word":"international","hi":[0,5]},{"word":"intramural","hi":[0,5]}]}},{"mood":"happy","cap":"intercede = inter- + cedere (go)","say":"Take intercede. Inter, between, plus the Latin cedere, to go. To go between two parties to help them, like stepping into the middle of an argument.","show":{"t":"breakdown","word":"intercede","hi":[0,5],"parts":[{"txt":"inter-","gloss":"between"},{"txt":"cedere","gloss":"to go"}]}},{"mood":"oops","cap":"intractable uses in-, NOT intra-!","say":"Watch out for an imposter. Intractable looks like intra, but it's really in, meaning not, plus tractable. It means not able to be handled. Always check before you assume.","show":{"t":"word","word":"intractable","hi":[0,2]}},{"mood":"excited","cap":"between two, or within one?","say":"So always ask yourself. Between two or more things means inter. Inside one single thing means intra. That tiny letter holds the whole meaning.","show":{"t":"glyph","text":"inter- · intra-","sub":"two vs one"}}]},"20":{"label":"trans- / per-","scenes":[{"mood":"happy","cap":"trans- = across, per- = through","say":"Two travelers. Trans, spelled T R A N S, means across or beyond. Per, spelled P E R, means through, or thoroughly.","show":{"t":"glyph","text":"trans- · per-","sub":"across · through"}},{"mood":"happy","cap":"transcend = trans- + scandere (climb)","say":"Take transcend. Trans, across, plus the Latin scandere, to climb. To climb across and beyond your limits, to go higher than before.","show":{"t":"breakdown","word":"transcend","hi":[0,5],"parts":[{"txt":"trans-","gloss":"across, beyond"},{"txt":"scandere","gloss":"to climb"}]}},{"mood":"happy","cap":"perfidy = per- + fides (faith)","say":"Now per. Take perfidy. Per, through, plus the Latin fides, faith. Faith broken all the way through, which means treachery, a deep betrayal.","show":{"t":"breakdown","word":"perfidy","hi":[0,3],"parts":[{"txt":"per-","gloss":"through"},{"txt":"fides","gloss":"faith"}]}},{"mood":"oops","cap":"perennial = double-n from annus","say":"Watch the spelling here. Perennial, per plus the Latin annus, year, means lasting through all the years. And it gets a double n from annus.","show":{"t":"breakdown","word":"perennial","hi":[0,3],"parts":[{"txt":"per-","gloss":"through"},{"txt":"annus","gloss":"year"}]}},{"mood":"excited","cap":"across vs through — pick the path","say":"So picture the movement. Trans crosses over and beyond. Per pushes all the way through. Get the path right and these words open up.","show":{"t":"glyph","text":"trans- · per-","sub":"across vs through"}}]},"21":{"label":"Latin ab- / abs-","scenes":[{"mood":"happy","cap":"ab- = away from, off","say":"Meet the prefix ab, spelled A B. It comes from Latin and it always means away from, or off. It signals departure.","show":{"t":"glyph","text":"ab-","sub":"away from · off"}},{"mood":"happy","cap":"aberrant = ab- + errare (wander)","say":"Take aberrant. Ab, away, plus the Latin errare, to wander. Wandering away from the normal path, which means strange or off-course.","show":{"t":"breakdown","word":"aberrant","hi":[0,2],"parts":[{"txt":"ab-","gloss":"away"},{"txt":"errare","gloss":"to wander"}]}},{"mood":"oops","cap":"before s/t → abs-","say":"Here's a shape change. Before s or t, ab becomes abs. Abstain, abs plus the Latin tenere, to hold, means to hold yourself away from something, to refrain.","show":{"t":"breakdown","word":"abstain","hi":[0,3],"parts":[{"txt":"abs-","gloss":"away"},{"txt":"tenere","gloss":"to hold"}]}},{"mood":"happy","cap":"before v → a-","say":"And before v, it shortens to just a. Avert, a plus the Latin vertere, to turn, means to turn away. Same prefix, just trimmed down.","show":{"t":"breakdown","word":"avert","hi":[0,1],"parts":[{"txt":"a-","gloss":"away (from ab-)"},{"txt":"vertere","gloss":"to turn"}]}},{"mood":"excited","cap":"ab- · abs- · a- — all mean away","say":"So three shapes, one idea. Ab, abs, and a all mean away from. Spot the hidden departure and you'll spell every one of them right.","show":{"t":"glyph","text":"ab- abs- a-","sub":"always away"}}]},"22":{"label":"Latin ad-","scenes":[{"mood":"happy","cap":"ad- = toward, near","say":"Meet the prefix ad, spelled A D. It comes from Latin and means toward, near, or in addition to.","show":{"t":"glyph","text":"ad-","sub":"toward · near"}},{"mood":"excited","cap":"ad- doubles the next consonant","say":"Here's the wild part. Ad is the most enthusiastic copycat in Latin. Its d changes to match the next consonant and doubles it. Before c it's ac, before l it's al, before p it's ap.","show":{"t":"glyph","text":"ad → ac/al/ap/as/at","sub":"the d copies the next letter"}},{"mood":"happy","cap":"alleviate = al- + levis (light)","say":"Take alleviate. The ad turned into al before the root, plus the Latin levis, light. To make something lighter, to ease pain. That double l is the prefix.","show":{"t":"breakdown","word":"alleviate","hi":[0,2],"parts":[{"txt":"al-","gloss":"toward (from ad-)"},{"txt":"levis","gloss":"light"}]}},{"mood":"happy","cap":"assiduous = as- + sedere (sit)","say":"Or assiduous. Ad became as, plus the Latin sedere, to sit. Sitting steadily at your work, which means hardworking and careful. The double s gives it away.","show":{"t":"breakdown","word":"assiduous","hi":[0,2],"parts":[{"txt":"as-","gloss":"toward (from ad-)"},{"txt":"sedere","gloss":"to sit"}]}},{"mood":"excited","cap":"The doubled letter IS ad-","say":"So whenever you see a doubled consonant near the start, suspect ad. Acquire, append, attrition. That double letter is really toward in disguise.","show":{"t":"list","items":[{"word":"acquire","hi":[0,2]},{"word":"append","hi":[0,2]}]}}]},"23":{"label":"anti / hyper / hypo","scenes":[{"mood":"happy","cap":"anti = against, hyper = over, hypo = under","say":"Three Greek prefixes. Anti, spelled A N T I, means against. Hyper, H Y P E R, means over or too much. And hypo, H Y P O, means under, or too little.","show":{"t":"glyph","text":"anti · hyper · hypo","sub":"against · over · under"}},{"mood":"happy","cap":"antidote = anti- + didonai (give)","say":"Take antidote. Anti, against, plus the Greek didonai, to give. Something given against a poison, to fight it.","show":{"t":"breakdown","word":"antidote","hi":[0,4],"parts":[{"txt":"anti-","gloss":"against"},{"txt":"didonai","gloss":"to give"}]}},{"mood":"love","cap":"hyperbole = hyper- + ballein (throw)","say":"Here's a delightful one. Hyperbole, hyper plus the Greek ballein, to throw. Throwing way over the top, which is wild exaggeration. And surprise, that last e is spoken.","show":{"t":"breakdown","word":"hyperbole","hi":[0,5],"parts":[{"txt":"hyper-","gloss":"over"},{"txt":"ballein","gloss":"to throw"}]}},{"mood":"happy","cap":"hyper- vs hypo- in medicine","say":"In medicine these pair up neatly. Hypertension is blood pressure too high, hypotension too low. Know the prefix and you know the diagnosis.","show":{"t":"list","items":[{"word":"hypertension","hi":[0,5]},{"word":"hypotension","hi":[0,4]}]}},{"mood":"oops","cap":"hypocrisy = H-Y-P-O-C-R-I-S-Y, not -acy","say":"One spelling trap. Hypocrisy, hypo plus the Greek krinein, to judge, ends I S Y, not A C Y. Picture judging from under a mask, pretending values you don't have.","show":{"t":"word","word":"hypocrisy","hi":[0,4]}}]},"24":{"label":"auto/tele/micro/mega","scenes":[{"mood":"happy","cap":"auto = self, tele = far","say":"Five Greek prefixes of size and distance. Auto, spelled A U T O, means self. Tele, spelled T E L E, means far away.","show":{"t":"glyph","text":"auto · tele","sub":"self · far"}},{"mood":"happy","cap":"autodidact = auto- + didaskein (teach)","say":"Take autodidact. Auto, self, plus the Greek didaskein, to teach. A person who taught themselves, with no teacher at all.","show":{"t":"breakdown","word":"autodidact","hi":[0,4],"parts":[{"txt":"auto-","gloss":"self"},{"txt":"didaskein","gloss":"to teach"}]}},{"mood":"happy","cap":"telekinesis = tele- + kinesis (movement)","say":"Now tele. Take telekinesis. Tele, far, plus the Greek kinesis, movement. Moving things from a distance, just by thinking about them.","show":{"t":"breakdown","word":"telekinesis","hi":[0,4],"parts":[{"txt":"tele-","gloss":"far"},{"txt":"kinesis","gloss":"movement"}]}},{"mood":"happy","cap":"micro = small, macro = large, mega = huge","say":"Three sizes. Micro means small, macro means large, and mega means very large. A microcosm is a small world, a macrocosm the whole one, and a megalith a giant stone like Stonehenge.","show":{"t":"glyph","text":"micro · macro · mega","sub":"small · large · huge"}},{"mood":"excited","cap":"Know the roots, spell the word","say":"Each word is built precisely from Greek parts. Automaton, telepathy, megalomaniac. If you know the roots, you can spell every piece in order.","show":{"t":"list","items":[{"word":"automaton","hi":[0,4]},{"word":"telepathy","hi":[0,4]}]}}]},"25":{"label":"bio/geo/photo/hydro","scenes":[{"mood":"happy","cap":"Five Greek science prefixes","say":"Five Greek prefixes power all of science. Bio means life, geo means earth, photo means light, hydro means water, and thermo means heat.","show":{"t":"glyph","text":"bio·geo·photo·hydro·thermo","sub":"life·earth·light·water·heat"}},{"mood":"happy","cap":"biopsy = bio- + opsis (seeing)","say":"Take biopsy. Bio, spelled B I O, life, plus the Greek opsis, seeing. Looking at living tissue to check it for disease.","show":{"t":"breakdown","word":"biopsy","hi":[0,3],"parts":[{"txt":"bio-","gloss":"life"},{"txt":"opsis","gloss":"seeing"}]}},{"mood":"happy","cap":"hydrolysis = hydro- + lysis (breaking)","say":"Take hydrolysis. Hydro, spelled H Y D R O, water, plus the Greek lysis, breaking. Breaking something apart using water.","show":{"t":"breakdown","word":"hydrolysis","hi":[0,5],"parts":[{"txt":"hydro-","gloss":"water"},{"txt":"lysis","gloss":"breaking"}]}},{"mood":"oops","cap":"photo- always ph, never f!","say":"Here's the big spelling rule. Because these are Greek, photo is spelled P H O T O, never with an f. Photosynthesis, photon, photograph. Always p h.","show":{"t":"word","word":"photosynthesis","hi":[0,5]}},{"mood":"excited","cap":"Stack the parts: geo + thermo","say":"And you can stack them. Geothermal joins geo, earth, with thermo, heat. Earth-heat, the warmth deep inside our planet. Learn five prefixes, unlock dozens of words.","show":{"t":"breakdown","word":"geothermal","hi":[0,3],"parts":[{"txt":"geo-","gloss":"earth"},{"txt":"thermo-","gloss":"heat"}]}}]},"26":{"label":"Greek body prefixes","scenes":[{"mood":"happy","cap":"neuro·cardio·osteo·psycho·derm·hem","say":"Six Greek prefixes name the body. Neuro is nerve, cardio is heart, osteo is bone, psycho is mind, derm is skin, and hem is blood.","show":{"t":"glyph","text":"neuro·cardio·osteo","sub":"nerve · heart · bone"}},{"mood":"happy","cap":"pericardium = peri- + cardio (heart)","say":"Take pericardium. Cardio, spelled C A R D I O, heart, with peri, around. The membrane that wraps around the heart.","show":{"t":"breakdown","word":"pericardium","hi":[4,4],"parts":[{"txt":"peri-","gloss":"around"},{"txt":"cardio","gloss":"heart"}]}},{"mood":"happy","cap":"osteoporosis = osteo- + poros (passage)","say":"Take osteoporosis. Osteo, spelled O S T E O, bone, plus the Greek poros, passage. Bones turning porous and full of holes, so they grow fragile.","show":{"t":"breakdown","word":"osteoporosis","hi":[0,5],"parts":[{"txt":"osteo-","gloss":"bone"},{"txt":"poros","gloss":"passage"}]}},{"mood":"oops","cap":"psyche has a SILENT p","say":"Big trap with psycho. The p is silent but you must still write it. Psyche is spelled P S Y C H E. Always start that word with a quiet p.","show":{"t":"word","word":"psychosomatic","hi":[0,6]}},{"mood":"happy","cap":"hemorrhage = hem- + rhegnynai (burst)","say":"And hem, blood. Take hemorrhage, hem plus the Greek rhegnynai, to burst. Blood bursting out. Note the tricky double r and the silent h.","show":{"t":"breakdown","word":"hemorrhage","hi":[0,3],"parts":[{"txt":"hem-","gloss":"blood"},{"txt":"rhegnynai","gloss":"to burst"}]}}]},"27":{"label":"meta/para/epi/syn/peri","scenes":[{"mood":"happy","cap":"Five Greek positional prefixes","say":"Five Greek prefixes describe position. Meta means beyond or change, para means beside, epi means upon, syn means together, and peri means around.","show":{"t":"glyph","text":"meta·para·epi·syn·peri","sub":"beyond·beside·upon·together·around"}},{"mood":"happy","cap":"metaphor = meta- + pherein (carry)","say":"Take metaphor. Meta, spelled M E T A, beyond, plus the Greek pherein, to carry. Carrying a meaning beyond the literal, like calling time a thief.","show":{"t":"breakdown","word":"metaphor","hi":[0,4],"parts":[{"txt":"meta-","gloss":"beyond"},{"txt":"pherein","gloss":"to carry"}]}},{"mood":"happy","cap":"epiphany = epi- + phainein (show)","say":"Take epiphany. Epi, spelled E P I, upon, plus the Greek phainein, to show. A showing that comes upon you, a sudden bright realization.","show":{"t":"breakdown","word":"epiphany","hi":[0,3],"parts":[{"txt":"epi-","gloss":"upon"},{"txt":"phainein","gloss":"to show"}]}},{"mood":"oops","cap":"syn- → sym- before b, m, p","say":"Here's a spelling shift. Syn, together, becomes sym before b, m, or p. So we write symphony and sympathy with an m, but syntax and synonym with an n.","show":{"t":"glyph","text":"syn → sym","sub":"before b · m · p"}},{"mood":"excited","cap":"peri- = around: perimeter, periphery","say":"And peri means around. Perimeter, peri plus the Greek metron, measure, is the measurement around a shape. Learn these five and position words snap right into place.","show":{"t":"breakdown","word":"perimeter","hi":[0,4],"parts":[{"txt":"peri-","gloss":"around"},{"txt":"metron","gloss":"measure"}]}}]},"28":{"label":"Latin & Greek numbers","scenes":[{"mood":"happy","cap":"English counts in two old languages.","say":"English borrows its number prefixes from both Latin and Greek. Learn both sets, and you can decode words from either language at sight.","show":{"t":"glyph","text":"uni · mono","sub":"one · one"}},{"mood":"happy","cap":"uni- (Latin) and mono- (Greek) both = one.","say":"For one, Latin gives us uni, spelled U N I, as in unicorn, one horn. Greek gives us mono, as in monologue, a speech you make all by yourself.","show":{"t":"breakdown","word":"unicorn","hi":[0,3],"parts":[{"txt":"uni","gloss":"one"},{"txt":"corn","gloss":"horn"}]}},{"mood":"happy","cap":"Two: bi-/di-; dichotomy = a split in two.","say":"For two, Latin gives bi, as in bicycle, two wheels. Greek gives di, spelled D I, as in dichotomy, a division into two parts.","show":{"t":"list","items":[{"word":"bicycle","hi":[0,2]},{"word":"dichotomy","hi":[0,2]}]}},{"mood":"excited","cap":"tri- + ptychē (fold) → triptych","say":"Three is the same in both languages, tri. Take triptych, spelled T R I, plus the Greek ptyche, meaning fold. It is art on three folded panels.","show":{"t":"breakdown","word":"triptych","hi":[0,3],"parts":[{"txt":"tri","gloss":"three"},{"txt":"ptych","gloss":"fold"}]}},{"mood":"oops","cap":"millennium = mille + annum → double-l AND double-n","say":"Watch out for millennium. It is mille, a thousand, plus annum, year. That gives a double l and a double n, and it is one of the most misspelled words in English.","show":{"t":"breakdown","word":"millennium","hi":[3,4],"parts":[{"txt":"mille","gloss":"thousand"},{"txt":"annum","gloss":"year"}]}}]},"29":{"label":"many & all prefixes","scenes":[{"mood":"happy","cap":"Four ways to say many or all.","say":"There are four ways to say many or all. Greek poly and Latin multi both mean many. Latin omni and Greek pan both mean all.","show":{"t":"glyph","text":"poly · pan","sub":"many · all"}},{"mood":"happy","cap":"poly- + glotta (tongue) → polyglot","say":"Poly, spelled P O L Y, means many. Take polyglot, poly plus the Greek glotta, meaning tongue. A polyglot speaks many tongues, or languages.","show":{"t":"breakdown","word":"polyglot","hi":[0,4],"parts":[{"txt":"poly","gloss":"many"},{"txt":"glotta","gloss":"tongue"}]}},{"mood":"excited","cap":"omni- + vorare (eat) → omnivore","say":"Omni, spelled O M N I, means all. Take omnivore, omni plus the Latin vorare, to eat. An omnivore eats all kinds of food.","show":{"t":"breakdown","word":"omnivore","hi":[0,4],"parts":[{"txt":"omni","gloss":"all"},{"txt":"vorare","gloss":"to eat"}]}},{"mood":"love","cap":"omni- + bus (for all) → bus!","say":"Here is a delightful one. Omnibus means for all. And our little word bus is just omnibus with the front chopped off. A bus really is the for everyone wagon.","show":{"t":"breakdown","word":"omnibus","hi":[0,4],"parts":[{"txt":"omni","gloss":"all"},{"txt":"bus","gloss":"for all"}]}},{"mood":"oops","cap":"pan- = Greek; polyphony uses ph, not f.","say":"Pan means all, as in panorama, an all around view. And remember the Greek signal. Polyphony is spelled with a p h, not an f, because Greek loves p h.","show":{"t":"breakdown","word":"panorama","hi":[0,3],"parts":[{"txt":"pan","gloss":"all"},{"txt":"horama","gloss":"view"}]}}]},"30":{"label":"-tion / -sion / -cion","scenes":[{"mood":"happy","cap":"One /shun/ sound, three spellings.","say":"This is the most common suffix in English, from the Latin tionem. It says one sound, shun, but it can be spelled three ways, and the root before it decides which.","show":{"t":"glyph","text":"-tion","sub":"action · state"}},{"mood":"happy","cap":"Root ends in t/te → -tion (act → action)","say":"Here is the rule. If the root ends in t or t e, you use t i o n. Act becomes action. Create becomes creation. The root ending is your guide.","show":{"t":"list","items":[{"word":"action","hi":[3,4]},{"word":"creation","hi":[4,4]}]}},{"mood":"happy","cap":"Root ends in d/se → -sion (extend → extension)","say":"But if the root ends in d, or in s e, you switch to s i o n. Extend becomes extension. Revise becomes revision. Same shun sound, different spelling.","show":{"t":"list","items":[{"word":"extension","hi":[6,3]},{"word":"revision","hi":[5,3]}]}},{"mood":"excited","cap":"predilection = pre- + dilectus (chosen)","say":"Now a championship word. Predilection means a strong preference. It is pre, before, plus the Latin dilectus, meaning chosen. Something you choose ahead of time.","show":{"t":"breakdown","word":"predilection","hi":[9,4],"parts":[{"txt":"pre","gloss":"before"},{"txt":"dilectus","gloss":"chosen"}]}},{"mood":"oops","cap":"-tion is always ONE syllable = /shun/","say":"Watch out on the long ones. The ending is always just one syllable, shun. Exacerbation has five syllables, and that whole shun is only the last one. Count slowly.","show":{"t":"word","word":"exacerbation","hi":[8,4]}}]},"31":{"label":"-ous adjective family","scenes":[{"mood":"happy","cap":"-ous = full of / having the quality of.","say":"The ending o u s means full of, or having the quality of. It comes in four flavors, ous, ious, eous, and uous, and the noun base decides which one you need.","show":{"t":"glyph","text":"-ous","sub":"full of"}},{"mood":"excited","cap":"The -acious cluster from Latin -ax.","say":"There is a treasure cluster spelled a c i o u s, from the Latin ax stem. Tenacious means holding fast. Voracious means devouring. Audacious means bold and fearless.","show":{"t":"list","items":[{"word":"tenacious","hi":[4,5]},{"word":"voracious","hi":[4,5]}]}},{"mood":"happy","cap":"igneous = ignis (fire) + -eous","say":"The e o u s words often have an e in the base. Take igneous, from the Latin ignis, meaning fire. Igneous rock is rock formed from volcanic fire.","show":{"t":"breakdown","word":"igneous","hi":[3,4],"parts":[{"txt":"ign","gloss":"fire"},{"txt":"-eous","gloss":"having the quality"}]}},{"mood":"love","cap":"facetious holds A-E-I-O-U in order!","say":"Here is a fun one. Facetious, which means not to be taken seriously, secretly contains all five vowels, a, e, i, o, u, in perfect order. A spelling gift to remember.","show":{"t":"word","word":"facetious","hi":[0,9]}},{"mood":"oops","cap":"mischievous = 3 syllables, no extra -i-!","say":"Big trap. Mischievous is three syllables, mis chiev ous, with no extra i. Same for grievous. Adding a sneaky extra i is the most common mistake in this family.","show":{"t":"word","word":"mischievous","hi":[7,4]}}]},"32":{"label":"-able / -ible","scenes":[{"mood":"happy","cap":"One sound, two spellings: -able / -ible.","say":"Two spellings make one sound, uh bul. The trick is asking whether the root can stand on its own as a real English word.","show":{"t":"glyph","text":"-able / -ible","sub":"capable of being"}},{"mood":"happy","cap":"Whole word → -able (depend → dependable)","say":"If the root is a complete English word, use a b l e. Comfort is a word, so comfortable. Depend is a word, so dependable. Whole word, then able.","show":{"t":"list","items":[{"word":"dependable","hi":[6,4]},{"word":"breakable","hi":[5,4]}]}},{"mood":"happy","cap":"Latin stem → -ible (vis- → visible)","say":"But if the root is only a Latin stem that cannot stand alone, use i b l e. Aud cannot stand alone, so audible. Vis cannot stand alone, so visible.","show":{"t":"breakdown","word":"visible","hi":[3,4],"parts":[{"txt":"vis","gloss":"see"},{"txt":"-ible","gloss":"able to be"}]}},{"mood":"happy","cap":"Keep the e after c/g (notice → noticeable)","say":"After a soft c or g, keep the e to protect the sound. Notice becomes noticeable. Change becomes changeable. That little e is the softening guard.","show":{"t":"word","word":"noticeable","hi":[5,5]}},{"mood":"oops","cap":"irresistible = double-r from ir- assimilation","say":"Watch out for irresistible. It takes i b l e, and it has a double r, because the prefix in changed to ir to match the next letter. It means impossible to resist.","show":{"t":"word","word":"irresistible","hi":[9,3]}}]},"33":{"label":"-ance / -ence","scenes":[{"mood":"happy","cap":"Adjective ending tells you the noun ending.","say":"These suffixes turn adjectives into abstract nouns. The core rule is simple. An adjective ending in a n t becomes a n c e, and one ending in e n t becomes e n c e.","show":{"t":"glyph","text":"-ance / -ence","sub":"state · quality"}},{"mood":"happy","cap":"relevant → relevance; different → difference","say":"So relevant, with a n t, becomes relevance, a n c e. And different, with e n t, becomes difference, e n c e. Read the adjective and the noun spells itself.","show":{"t":"list","items":[{"word":"relevance","hi":[7,3]},{"word":"difference","hi":[7,3]}]}},{"mood":"excited","cap":"benevolence = bene (good) + volence (wishing)","say":"Take a beautiful e n c e word, benevolence, which means a disposition to do good. It is built on bene, good, plus the idea of wishing. Wishing good toward others.","show":{"t":"breakdown","word":"benevolence","hi":[8,3],"parts":[{"txt":"bene","gloss":"good"},{"txt":"vol","gloss":"wishing"}]}},{"mood":"happy","cap":"-escent = in the process of becoming","say":"Notice e s c e n t, meaning in the process of becoming. Effervescent means becoming bubbly. Adolescent means becoming an adult. That s c cluster is the tricky part.","show":{"t":"breakdown","word":"adolescent","hi":[4,6],"parts":[{"txt":"adol","gloss":"growing up"},{"txt":"-escent","gloss":"becoming"}]}},{"mood":"oops","cap":"French traps: nuance, vengeance, obeisance","say":"Watch out for French words that break the rule. Nuance, a subtle difference, ends in a n c e. So does vengeance. And obeisance, a respectful bow, takes a n c e, not e n c e.","show":{"t":"word","word":"obeisance","hi":[6,3]}}]},"34":{"label":"abstract-noun suffixes","scenes":[{"mood":"happy","cap":"Five suffixes for qualities and conditions.","say":"Five suffixes turn words into abstract nouns, the names of qualities and conditions. Some come from Latin, and some from Old English, each covering its own territory.","show":{"t":"glyph","text":"-ity · -ness","sub":"state · quality"}},{"mood":"happy","cap":"-ity (Latin): brevity = brevis (short)","say":"The Latin ending is i t y, the most formal one. Brevity, the quality of being brief, comes from brevis, short. Gravity comes from gravis, heavy. The root names the quality.","show":{"t":"breakdown","word":"brevity","hi":[4,3],"parts":[{"txt":"brev","gloss":"short"},{"txt":"-ity","gloss":"state of"}]}},{"mood":"excited","cap":"-ness (Old English): bends to any adjective.","say":"The most flexible one is n e s s, from Old English. It joins almost any adjective. When no i t y form exists, n e s s is always there. That is why we can say weirdness.","show":{"t":"glyph","text":"-ness","sub":"Old English: any quality"}},{"mood":"happy","cap":"-dom (Old English): freedom = state of free","say":"The ending d o m means a realm or a state. Kingdom is the realm of a king. Freedom is the state of being free. Wisdom is the state of being wise.","show":{"t":"breakdown","word":"freedom","hi":[4,3],"parts":[{"txt":"free","gloss":"free"},{"txt":"-dom","gloss":"state of"}]}},{"mood":"happy","cap":"-ship: skill, relationship, or status.","say":"Lastly, s h i p carries a sense of skill or status. Seamanship is the skill of a seaman. Friendship is the bond between friends. Both the role and the craft live in s h i p.","show":{"t":"list","items":[{"word":"scholarship","hi":[8,4]},{"word":"friendship","hi":[6,4]}]}}]},"35":{"label":"-ism / -ist","scenes":[{"mood":"happy","cap":"-ism = the belief; -ist = the person.","say":"Here is a perfect pair from Greek. The ending i s m is a belief or practice, and i s t is the person who holds it. Know the ism, and you instantly know the ist.","show":{"t":"glyph","text":"-ism / -ist","sub":"doctrine · practitioner"}},{"mood":"happy","cap":"nihilism = nihil (nothing) + -ism","say":"Take nihilism, spelled with the ending i s m. It comes from the Latin nihil, meaning nothing. It is the belief that nothing has meaning. A nihilist is one who holds it.","show":{"t":"breakdown","word":"nihilism","hi":[5,3],"parts":[{"txt":"nihil","gloss":"nothing"},{"txt":"-ism","gloss":"belief"}]}},{"mood":"happy","cap":"monotheism = mono (one) + theos (god)","say":"Many beliefs use this. Monotheism is mono, one, plus theos, god, the belief in one god. Polytheism uses poly, many, the belief in many gods.","show":{"t":"breakdown","word":"monotheism","hi":[7,3],"parts":[{"txt":"mono","gloss":"one"},{"txt":"theos","gloss":"god"}]}},{"mood":"oops","cap":"schism = S-C-H-I-S-M; the sch sounds /sk/","say":"Big trap. Schism means a split in a group, and it comes from the Greek skhizein, to split. It is spelled s c h i s m, but the s c h sounds like sk. Do not write shism.","show":{"t":"breakdown","word":"schism","hi":[0,3],"parts":[{"txt":"skhizein","gloss":"to split"}]}},{"mood":"oops","cap":"narcissism = double-s from Narcissus","say":"And narcissism, excessive self love, takes a double s, because it comes from the name Narcissus. So picture two s letters right in the middle, then the ending i s m.","show":{"t":"word","word":"narcissism","hi":[4,2]}}]},"36":{"label":"-ology / -ographer","scenes":[{"mood":"happy","cap":"logos = word/reason/study.","say":"The Greek logos means word, reason, or study. So the ending o l o g y means the study of whatever root comes before it. Know the root, and you know the field.","show":{"t":"glyph","text":"-ology","sub":"study of"}},{"mood":"happy","cap":"ornis (bird) + -ology → ornithology","say":"Take ornithology, the study of birds. It is ornis, the Greek for bird, plus o l o g y, study of. Add i s t for the person, and you get ornithologist.","show":{"t":"breakdown","word":"ornithology","hi":[7,4],"parts":[{"txt":"ornith","gloss":"bird"},{"txt":"-ology","gloss":"study of"}]}},{"mood":"excited","cap":"dendro (tree) + chron + -ology","say":"A long one spells itself once you split it. Dendrochronology is dendro, tree, plus chron, time, plus o l o g y. It is dating events by counting the rings of trees.","show":{"t":"breakdown","word":"dendrochronology","hi":[11,5],"parts":[{"txt":"dendro","gloss":"tree"},{"txt":"chron","gloss":"time"}]}},{"mood":"oops","cap":"etymology vs entomology — watch letter 2!","say":"Watch this confusable pair. Etymology, e t y, is the study of word origins, from etymon, true form. Entomology, e n t o, is the study of insects. The second letter is the tell.","show":{"t":"list","items":[{"word":"etymology","hi":[0,3]},{"word":"entomology","hi":[0,4]}]}},{"mood":"happy","cap":"-ographer = one who writes/records.","say":"A cousin ending is o g r a p h e r, one who writes or records. A choreographer designs dances. A lexicographer writes dictionaries. Same family, focused on recording.","show":{"t":"glyph","text":"-ographer","sub":"one who records"}}]},"37":{"label":"Greek medical suffixes","scenes":[{"mood":"happy","cap":"Six suffixes decode any medical word.","say":"Six Greek suffixes can decode almost any medical word, even one you have never seen. The root tells you where in the body, and the suffix tells you what is happening.","show":{"t":"glyph","text":"-itis · -osis","sub":"medical signals"}},{"mood":"happy","cap":"-itis = inflammation (gingiva → gums)","say":"The ending i t i s always means inflammation. Gingivitis is inflammation of the gingiva, your gums. Laryngitis is an inflamed voice box. Simple and reliable.","show":{"t":"breakdown","word":"gingivitis","hi":[7,4],"parts":[{"txt":"gingiva","gloss":"gum"},{"txt":"-itis","gloss":"inflammation"}]}},{"mood":"excited","cap":"-ectomy = ek (out) + tome (cutting)","say":"Here is the key contrast. The ending e c t o m y is ek, out, plus tome, cutting. It means surgical removal. An appendectomy removes the appendix entirely.","show":{"t":"breakdown","word":"appendectomy","hi":[7,5],"parts":[{"txt":"ek","gloss":"out"},{"txt":"tome","gloss":"cutting"}]}},{"mood":"happy","cap":"-tomy = cut INTO; dichotomy = dikho (in two)","say":"But plain t o m y just means cutting into, not removing. Dichotomy is dikho, in two, plus tome. So remember, e c t o m y removes, while t o m y only cuts open.","show":{"t":"breakdown","word":"dichotomy","hi":[6,3],"parts":[{"txt":"dikho","gloss":"in two"},{"txt":"tome","gloss":"cutting"}]}},{"mood":"happy","cap":"-scope = skopein (to look)","say":"Two more. The ending scope is from skopein, to look. A periscope looks around. And meter, from metron, means measure, as in a barometer that measures pressure.","show":{"t":"glyph","text":"-scope · -meter","sub":"look · measure"}}]},"38":{"label":"agent suffixes","scenes":[{"mood":"happy","cap":"A person who does — from six languages.","say":"When English names a person who does something, it borrows from six languages, and the origin of the word decides the ending. The French ones trip spellers most.","show":{"t":"glyph","text":"-er / -or","sub":"a person who does"}},{"mood":"happy","cap":"Latin → -or; Old English → -er","say":"Latin roots take o r, like actor and narrator. Old English roots take e r, like builder and baker. If a word feels Latin, try o r first.","show":{"t":"list","items":[{"word":"actor","hi":[3,2]},{"word":"builder","hi":[5,2]}]}},{"mood":"happy","cap":"-ic drops c before -ian (magic → magician)","say":"The Latin ending i a n means one who practices. Words ending in i c drop the c before it. Magic becomes magician. Music becomes musician. The c quietly disappears.","show":{"t":"breakdown","word":"magician","hi":[5,3],"parts":[{"txt":"magic","gloss":"magic"},{"txt":"-ian","gloss":"one who does"}]}},{"mood":"excited","cap":"French -eur, always, not -er.","say":"French agent words always end in e u r, never e r. Connoisseur, chauffeur, and entrepreneur all take e u r. Picture the French spelling and you will not slip.","show":{"t":"word","word":"entrepreneur","hi":[9,3]}},{"mood":"oops","cap":"restaurateur — NO n before -ateur!","say":"Here is the famous trap. A person who runs a restaurant is a restaurateur, and there is no n before the e u r. It is not restauranteur. Drop that n and you have got it.","show":{"t":"word","word":"restaurateur","hi":[9,3]}}]},"39":{"label":"French -eau ending","scenes":[{"mood":"happy","cap":"e-a-u = one /oh/ sound (French).","say":"French words ending in e a u make a single sound, oh. Four letters, one syllable. Tableau, plateau, and bureau all end with that oh, spelled e a u.","show":{"t":"glyph","text":"-eau","sub":"= /oh/"}},{"mood":"happy","cap":"tableau, plateau, bureau all end /oh/.","say":"Take plateau, a flat raised land. The whole ending, p l a t plus e a u, lands on oh. Once you hear that oh at the end, picture the French e a u.","show":{"t":"word","word":"plateau","hi":[4,3]}},{"mood":"oops","cap":"plural -eaux: the x is silent!","say":"Now the classic trap. The plural adds an x, making e a u x, but that x is completely silent. One tableau, two tableaux, sound exactly the same. Never write e a u s.","show":{"t":"glyph","text":"-eaux","sub":"silent x plural"}},{"mood":"excited","cap":"portmanteau = porter (carry) + manteau (cloak)","say":"Here is a clever one. Portmanteau is porter, to carry, plus manteau, a cloak. It is a suitcase that carries two things, and it also names a word made of two words, like brunch.","show":{"t":"breakdown","word":"portmanteau","hi":[4,7],"parts":[{"txt":"porter","gloss":"carry"},{"txt":"manteau","gloss":"cloak"}]}},{"mood":"happy","cap":"See -eau → French, /oh/, double-check spelling.","say":"So whenever you spot e a u, think French, and think oh. Beau, nouveau, flambeau, they all follow the pattern. Hear the oh, and the spelling falls into place.","show":{"t":"list","items":[{"word":"beau","hi":[1,3]},{"word":"flambeau","hi":[5,3]}]}}]},"40":{"label":"French -oir / -oire","scenes":[{"mood":"happy","cap":"-oir sounds like /wahr/ (French).","say":"French words ending in o i r carry a special sound, wahr, almost like the word war with a w in front. It is a pattern you simply cannot guess without knowing it.","show":{"t":"glyph","text":"-oir","sub":"= /wahr/"}},{"mood":"happy","cap":"abattoir = abattre (to strike down)","say":"Take abattoir, a slaughterhouse. It comes from the French abattre, to strike down, and it ends in o i r, sounding uh bat wahr. Hear that wahr, and write o i r.","show":{"t":"breakdown","word":"abattoir","hi":[5,3],"parts":[{"txt":"abattre","gloss":"to strike down"}]}},{"mood":"love","cap":"Trick: -oir = \"war\" with a /w/ added.","say":"Here is a lovely memory trick. The ending sounds like the word war with a w added, wahr. So boudoir is boo plus d plus war. Once you hear it, the spelling is automatic.","show":{"t":"word","word":"boudoir","hi":[4,3]}},{"mood":"oops","cap":"reservoir = R-E-S-E-R-V-O-I-R, keep the r!","say":"Watch out for reservoir, a place where water is stored. People drop the middle r, or add an extra e at the end. Say it slowly, res, er, voir, three clean syllables.","show":{"t":"word","word":"reservoir","hi":[6,3]}},{"mood":"happy","cap":"Some keep -oire (repertoire).","say":"A few French words keep the final e, spelled o i r e. Repertoire, your set of skills, ends in o i r e. Others drop it, like memoir. When unsure, ask if the word is French.","show":{"t":"word","word":"repertoire","hi":[6,4]}}]},"41":{"label":"French -ette","scenes":[{"mood":"happy","cap":"-ette = a small version (French).","say":"The French ending e t t e means a little version of something. It always has a double t, and it always ends in a silent e. Small, delicate, and tidy.","show":{"t":"glyph","text":"-ette","sub":"small version"}},{"mood":"love","cap":"marionette = \"little Mary\" puppet.","say":"A marionette is a small puppet, and the name means little Mary. The ending e t t e makes the Mary tiny. A delightful way to remember the little ending.","show":{"t":"word","word":"marionette","hi":[6,4]}},{"mood":"happy","cap":"vigne (vine) → vignette","say":"Take vignette, a brief literary sketch. It comes from vigne, the French for vine, plus e t t e. It is a tiny vine like decoration, then a tiny scene in writing.","show":{"t":"breakdown","word":"vignette","hi":[5,3],"parts":[{"txt":"vigne","gloss":"vine"},{"txt":"-ette","gloss":"small"}]}},{"mood":"oops","cap":"Always double-t: P-I-R-O-U-E-T-T-E.","say":"Big trap. The ending always has a double t. Pirouette, a spinning ballet turn, is spelled with t t before that silent e. Never write a single t in these words.","show":{"t":"word","word":"pirouette","hi":[6,3]}},{"mood":"excited","cap":"Hear the vowel before t → -ette, not -et.","say":"Here is the key listening trick. If you hear a vowel before the final t, like pi roo et, it is e t t e. But ballet and bouquet hide a silent t, so they take just e t.","show":{"t":"list","items":[{"word":"roulette","hi":[5,3]},{"word":"bouquet","hi":[5,2]}]}}]},"42":{"label":"French -esque/-ique","scenes":[{"mood":"happy","cap":"-esque = \"in the style of\"","say":"Let's meet the French ending esque, spelled E, S, Q, U, E. It means in the style of something. Picturesque means like a picture, so charming to look at.","show":{"t":"glyph","text":"-esque","sub":"in the style of"}},{"mood":"happy","cap":"grotta (cave) → grotesque","say":"Grotesque comes from grotta, meaning a cave or grotto, and it means bizarre and distorted. Arabesque means in the Arabic style, and statuesque means like a statue, impressively tall.","show":{"t":"breakdown","word":"grotesque","hi":[0,5],"parts":[{"txt":"grott","gloss":"cave"},{"txt":"-esque","gloss":"in the style of"}]}},{"mood":"happy","cap":"-ique signals French, sounds like /eek/","say":"The ending ique also comes from French, and it sounds like eek. Boutique is a small shop, mystique is an air of mystery, and antique is an old object.","show":{"t":"list","items":[{"word":"boutique","hi":[4,4]},{"word":"mystique","hi":[4,4]}]}},{"mood":"excited","cap":"q is ALWAYS followed by u","say":"Here is the most reliable rule. In all of these endings, q is always followed by u. English never writes q on its own, so for every esque and ique word, write Q, U together.","show":{"t":"glyph","text":"qu","sub":"never q alone"}},{"mood":"oops","cap":"arabesque, NOT arbaesque","say":"Watch the spelling trap. Arabesque is spelled A, R, A, B, E, S, Q, U, E, not arbaesque. And unique has only one u at the start. Hear the eek, and reach for Q, U, E.","show":{"t":"word","word":"arabesque","hi":[6,3]}}]},"43":{"label":"French silent letters","scenes":[{"mood":"happy","cap":"French keeps letters it no longer says","say":"Many French words in English carry silent final letters. They were once spoken in Old French, then fell silent, but the spelling stayed. The French rule is: spell what you don't hear.","show":{"t":"glyph","text":"silent","sub":"spell what you don't hear"}},{"mood":"happy","cap":"ballet = ba-LAY, silent -t","say":"Lots of these end in a silent t. Ballet sounds like ba-lay, bouquet sounds like boo-kay, and crochet sounds like kroh-shay. The t is written, but never spoken.","show":{"t":"list","items":[{"word":"ballet","hi":[5,1]},{"word":"bouquet","hi":[6,1]}]}},{"mood":"oops","cap":"corps = C-O-R-P-S, p AND s silent","say":"Now the trickiest one. Corps is spelled C, O, R, P, S, but both the p and the s are silent, so it just sounds like kor. Two letters you write and never say.","show":{"t":"word","word":"corps","hi":[3,2]}},{"mood":"happy","cap":"silent -s: rendezvous, debris","say":"Other words hide a silent s at the end. Rendezvous sounds like ron-day-voo, and debris sounds like duh-bree. In French, that final s was already silent, so English kept it silent too.","show":{"t":"list","items":[{"word":"debris","hi":[5,1]},{"word":"rendezvous","hi":[9,1]}]}},{"mood":"excited","cap":"French? → expect silent endings","say":"So here's your bee strategy. If a word comes from French, expect the final consonants to be silent, and put the stress on the last syllable. Picture the silent letters, and write them anyway.","show":{"t":"glyph","text":"French","sub":"silence at the ends"}}]},"44":{"label":"French -eur","scenes":[{"mood":"happy","cap":"-eur = \"one who does\"","say":"Meet the French ending eur, spelled E, U, R. It means one who does something. These words never use plain e-r, always e-u-r.","show":{"t":"glyph","text":"-eur","sub":"one who does"}},{"mood":"happy","cap":"chauffe (heat) + -eur → chauffeur","say":"Take chauffeur, one who drives. It comes from chauffe, meaning heat, because early cars needed coal-heating. Raconteur is one who tells stories, and saboteur is one who sabotages.","show":{"t":"breakdown","word":"chauffeur","hi":[6,3],"parts":[{"txt":"chauffe","gloss":"heat"},{"txt":"-eur","gloss":"one who does"}]}},{"mood":"oops","cap":"restaurateur — NO n before -eur","say":"Here's a famous trap. A restaurateur runs a restaurant, but there is no n before the eur. It's R, E, S, T, A, U, R, A, T, E, U, R. Don't sneak in the n from restaurant.","show":{"t":"word","word":"restaurateur","hi":[7,5]}},{"mood":"happy","cap":"entre + prendre + -eur → entrepreneur","say":"Entrepreneur breaks into entre, meaning between, plus prendre, to take, plus eur. So it's one who undertakes between supplier and customer. Spell it by syllables: en, tre, pre, neur.","show":{"t":"breakdown","word":"entrepreneur","hi":[9,3],"parts":[{"txt":"entre","gloss":"between"},{"txt":"prendre","gloss":"to take"},{"txt":"-eur","gloss":"one who does"}]}},{"mood":"excited","cap":"amateur — the eu comes before the r","say":"One more. Amateur comes from amat, meaning love, so it's someone who does a thing for love, not money. It's A, M, A, T, E, U, R. The e and u come before the r, never amatuer.","show":{"t":"breakdown","word":"amateur","hi":[4,3],"parts":[{"txt":"amat","gloss":"love"},{"txt":"-eur","gloss":"one who does"}]}}]},"45":{"label":"Italian doubles","scenes":[{"mood":"happy","cap":"Italian doubles consonants","say":"Italian loves doubled consonants, and English keeps them. A double consonant signals a short vowel just before it. Spotting the double often means spotting the Italian origin.","show":{"t":"glyph","text":"zz cc ll pp","sub":"short vowel before"}},{"mood":"happy","cap":"mozzarella: double-z AND double-l","say":"Look at mozzarella, spelled M, O, Z, Z, A, R, E, L, L, A. It has a double z and a double l. Intermezzo and palazzo also carry that double z.","show":{"t":"word","word":"mozzarella","hi":[2,2]}},{"mood":"happy","cap":"cappuccino: double-p AND double-c","say":"Cappuccino packs in two doublings: C, A, P, P, U, C, C, I, N, O, with a double p and a double c. Broccoli has a double c too.","show":{"t":"word","word":"cappuccino","hi":[5,2]}},{"mood":"oops","cap":"not everything doubles!","say":"But careful, not every Italian word doubles. Soprano comes from sopra, meaning above, and it has no double letter. Tempo doesn't double either. Only a short stressed vowel triggers the doubling.","show":{"t":"list","items":[{"word":"soprano"},{"word":"tempo"}]}},{"mood":"excited","cap":"paparazzi → singular paparazzo","say":"A fun one to finish. Paparazzi is spelled P, A, P, A, R, A, Z, Z, I, with a double z, and it's actually a plural. The singular is paparazzo. A bee might just ask you for that one.","show":{"t":"list","items":[{"word":"paparazzi","hi":[6,2]},{"word":"paparazzo","hi":[6,2]}]}}]},"46":{"label":"Italian music words","scenes":[{"mood":"happy","cap":"Italian = the language of music","say":"Italian is the language of classical music. Almost every volume marking and tempo marking has an Italian name. Piano means soft, and forte means loud or strong.","show":{"t":"glyph","text":"piano / forte","sub":"soft / loud"}},{"mood":"happy","cap":"staccare (detach) → staccato","say":"The technique words tell little stories. Staccato comes from staccare, to detach, so the notes are short and clipped. Legato comes from legare, to tie, so the notes flow smoothly connected.","show":{"t":"breakdown","word":"staccato","hi":[3,2],"parts":[{"txt":"staccare","gloss":"to detach"},{"txt":"-o","gloss":"Italian ending"}]}},{"mood":"happy","cap":"pizzicare (pinch) → pizzicato","say":"Pizzicato comes from pizzicare, to pinch, which is plucking the strings. Notice these technique words all end in o, the Italian masculine ending, and pizzicato keeps a double z too.","show":{"t":"breakdown","word":"pizzicato","hi":[2,2],"parts":[{"txt":"pizzicare","gloss":"to pinch"},{"txt":"-o","gloss":"Italian ending"}]}},{"mood":"excited","cap":"-issimo = most / very","say":"Here's a powerful ending: issimo, meaning most or very. Pianissimo means very soft, fortissimo means very loud, and prestissimo means as fast as possible. Note the double s in I, S, S, I, M, O.","show":{"t":"glyph","text":"-issimo","sub":"most · very"}},{"mood":"oops","cap":"pianissimo: P-I-A-N-I-S-S-I-M-O","say":"So watch that double s in the issimo words. Pianissimo is spelled P, I, A, N, I, S, S, I, M, O. Hear very soft, and remember to double the s right in the middle.","show":{"t":"word","word":"pianissimo","hi":[5,2]}}]},"47":{"label":"Greek graph / gram","scenes":[{"mood":"happy","cap":"graphein = to write","say":"Meet the Greek root graph, spelled G, R, A, P, H. It comes from graphein, meaning to write or record. When you see it, ask: what is being written down?","show":{"t":"glyph","text":"graph","sub":"write · record"}},{"mood":"happy","cap":"-graph = the instrument","say":"The ending graph names the instrument. A seismograph records earthquakes. Photograph breaks into photo, meaning light, plus graph, so it's written by light.","show":{"t":"breakdown","word":"photograph","hi":[5,5],"parts":[{"txt":"photo","gloss":"light"},{"txt":"graph","gloss":"write"}]}},{"mood":"excited","cap":"-gram = the thing written","say":"Switch to gram, and you get the thing that was written. An anagram breaks into ana, meaning again, plus gram, so its letters are rearranged again. A telegram is the distant message itself.","show":{"t":"breakdown","word":"anagram","hi":[3,4],"parts":[{"txt":"ana","gloss":"again"},{"txt":"gram","gloss":"thing written"}]}},{"mood":"happy","cap":"-graphy = the art / study","say":"Add graphy and you get the art or study. Calligraphy breaks into kalli, meaning beautiful, plus graphy, so it's beautiful writing. Choreography is the art of composing dances.","show":{"t":"breakdown","word":"calligraphy","hi":[5,6],"parts":[{"txt":"kalli","gloss":"beautiful"},{"txt":"graphy","gloss":"art of writing"}]}},{"mood":"excited","cap":"graph · gram · graphy — one family","say":"So one root, three jobs. Graph is the instrument, gram is the thing written, and graphy is the art of writing it. Spot G, R, A, P, H, and a whole family opens up.","show":{"t":"glyph","text":"graph","sub":"write · record"}}]},"48":{"label":"Greek phon / phone","scenes":[{"mood":"happy","cap":"phonē = sound, voice","say":"Meet the Greek root phon, spelled P, H, O, N. It comes from phonē, meaning sound or voice. The p-h spelling is its Greek identity card.","show":{"t":"glyph","text":"phon","sub":"sound · voice"}},{"mood":"oops","cap":"ph, never f, for Greek sound words","say":"Here's the trap. The p-h sounds exactly like an f, but in these Greek words you never write a plain f. Phonics, the study of sound and letters, is spelled with p-h.","show":{"t":"word","word":"phonics","hi":[0,2]}},{"mood":"happy","cap":"eu (good) / kako (bad) + phon","say":"Two opposites use it. Euphony breaks into eu, meaning good, plus phony, so it's pleasant sound. Cacophony breaks into kako, meaning bad, so it's harsh, unpleasant noise.","show":{"t":"breakdown","word":"cacophony","hi":[4,4],"parts":[{"txt":"kako","gloss":"bad"},{"txt":"phon","gloss":"sound"}]}},{"mood":"happy","cap":"mikros (small) + phone → microphone","say":"Many sound instruments use it. Microphone breaks into mikros, meaning small, plus phone, so it makes small voices big. Megaphone uses megas, large, and xylophone uses xylo, wood.","show":{"t":"breakdown","word":"microphone","hi":[5,5],"parts":[{"txt":"mikros","gloss":"small"},{"txt":"phone","gloss":"sound"}]}},{"mood":"excited","cap":"hear /f/ in a sound word → write ph","say":"So whenever you hear an f sound inside a learned sound word, reach for p-h, not f. Symphony, microphone, cacophony. The Greek p-h spelling never lets you down.","show":{"t":"glyph","text":"ph = /f/","sub":"Greek signal"}}]},"49":{"label":"Greek path / pathy","scenes":[{"mood":"happy","cap":"pathos = feeling, suffering","say":"Meet the Greek root path, spelled P, A, T, H. It comes from pathos, meaning feeling or suffering. In medicine it can also mean disease, and context tells you which.","show":{"t":"glyph","text":"path","sub":"feeling · suffering"}},{"mood":"happy","cap":"sym (with) + pathy → sympathy","say":"Look at feeling words. Sympathy breaks into sym, meaning with, plus pathy, so it's feeling with someone. Empathy uses em, meaning in, so it's feeling as if you were inside their experience.","show":{"t":"breakdown","word":"sympathy","hi":[3,5],"parts":[{"txt":"sym","gloss":"with"},{"txt":"pathy","gloss":"feeling"}]}},{"mood":"excited","cap":"a- (without) → apathy = no feeling","say":"Change the prefix, change the feeling. Apathy breaks into a, meaning without, plus pathy, so it's feeling nothing at all. Antipathy uses anti, against, so it's a deep dislike.","show":{"t":"breakdown","word":"apathy","hi":[1,5],"parts":[{"txt":"a-","gloss":"without"},{"txt":"pathy","gloss":"feeling"}]}},{"mood":"happy","cap":"-pathy = disease in medicine","say":"In medicine, pathy means disease. Neuropathy breaks into neuro, meaning nerve, plus pathy, so it's nerve disease. Cardiopathy is heart disease. The first part names which disease.","show":{"t":"breakdown","word":"neuropathy","hi":[5,5],"parts":[{"txt":"neuro","gloss":"nerve"},{"txt":"pathy","gloss":"disease"}]}},{"mood":"oops","cap":"same -pathy ending, swap the prefix","say":"Watch the pattern, not just the sound. Apathy, sympathy, and empathy all end the same way, P, A, T, H, Y, and only the prefix changes. Lock in pathy, then add the right front.","show":{"t":"list","items":[{"word":"apathy","hi":[1,5]},{"word":"empathy","hi":[2,5]}]}}]},"50":{"label":"Greek chron","scenes":[{"mood":"happy","cap":"khronos = time","say":"Meet the Greek root chron, spelled C, H, R, O, N. It comes from khronos, meaning time, and even the god of time. Every chron word relates to time.","show":{"t":"glyph","text":"chron","sub":"time"}},{"mood":"oops","cap":"ch sounds like /k/ here","say":"Here's the trap. In these Greek words the c-h sounds like a k, not like the c-h in chair. So you hear kron, but you write C, H, R, O, N every time.","show":{"t":"word","word":"chronic","hi":[0,2]}},{"mood":"happy","cap":"ana (against) + chron → anachronism","say":"Take anachronism. It breaks into ana, meaning against, plus chron, time, so it's something out of its proper time, like a smartphone in a medieval movie.","show":{"t":"breakdown","word":"anachronism","hi":[3,5],"parts":[{"txt":"ana","gloss":"against"},{"txt":"chron","gloss":"time"}]}},{"mood":"happy","cap":"syn (together) + chron → synchronize","say":"Or synchronize. It breaks into syn, meaning together, plus chron, time, so it means to make things happen at the very same time. A chronometer measures time precisely.","show":{"t":"breakdown","word":"synchronize","hi":[3,5],"parts":[{"txt":"syn","gloss":"together"},{"txt":"chron","gloss":"time"}]}},{"mood":"excited","cap":"hear /k/ in a learned word → ch","say":"So that c-h sounding like k is a reliable Greek signal. Chronology, chaos, chorus, character. Hear a k in a learned word, and reach for c-h, not k or c.","show":{"t":"glyph","text":"ch = /k/","sub":"Greek signal"}}]},"51":{"label":"Greek morph","scenes":[{"mood":"happy","cap":"morphē = form, shape","say":"Meet the Greek root morph, spelled M, O, R, P, H. It comes from morphē, meaning form or shape. It pops up anywhere words talk about shape or transformation.","show":{"t":"glyph","text":"morph","sub":"form · shape"}},{"mood":"excited","cap":"meta (change) + morph + -osis","say":"Take metamorphosis. It breaks into meta, meaning change, plus morph, form, plus osis, a process. So it's a complete change of form, like a caterpillar becoming a butterfly.","show":{"t":"breakdown","word":"metamorphosis","hi":[4,5],"parts":[{"txt":"meta","gloss":"change"},{"txt":"morph","gloss":"form"},{"txt":"-osis","gloss":"process"}]}},{"mood":"happy","cap":"a- (without) + morph → amorphous","say":"Now flip it. Amorphous breaks into a, meaning without, plus morph, form, so it means shapeless. Polymorphous uses poly, many, so it means having many forms.","show":{"t":"breakdown","word":"amorphous","hi":[1,5],"parts":[{"txt":"a-","gloss":"without"},{"txt":"morph","gloss":"form"}]}},{"mood":"happy","cap":"morpheme = smallest meaningful form","say":"In language, a morpheme is the smallest meaningful unit, like un, or tion. Morphology is the study of word forms. These little morphemes are the building blocks of every word.","show":{"t":"breakdown","word":"morpheme","hi":[0,5],"parts":[{"txt":"morph","gloss":"form"},{"txt":"-eme","gloss":"unit"}]}},{"mood":"oops","cap":"the ph in morph = /f/","say":"One spelling note. The p-h in morph sounds like an f, but it's still p-h, Greek phi. Morphine, the drug, even comes from Morpheus, the god of dreams who took any shape.","show":{"t":"word","word":"morphine","hi":[3,2]}}]},"52":{"label":"Greek scop / scope","scenes":[{"mood":"happy","cap":"skopein = to look at","say":"Meet the Greek root scope, spelled S, C, O, P, E. It comes from skopein, meaning to look at. Every scope word is an instrument for examining something.","show":{"t":"glyph","text":"scope","sub":"look at · examine"}},{"mood":"happy","cap":"mikros (small) + scope → microscope","say":"The front of the word tells you what it examines. Microscope breaks into mikros, meaning small, plus scope, so it looks at tiny things. Telescope uses tele, far, for distant things.","show":{"t":"breakdown","word":"microscope","hi":[5,5],"parts":[{"txt":"mikros","gloss":"small"},{"txt":"scope","gloss":"look at"}]}},{"mood":"happy","cap":"stethos (chest) + scope → stethoscope","say":"It works in medicine too. Stethoscope breaks into stethos, meaning chest, plus scope, so it examines the chest. Endoscope uses endo, within, to look inside the body.","show":{"t":"breakdown","word":"stethoscope","hi":[6,5],"parts":[{"txt":"stethos","gloss":"chest"},{"txt":"scope","gloss":"look at"}]}},{"mood":"excited","cap":"kalos + eidos + scope → kaleidoscope","say":"The big one is kaleidoscope, K, A, L, E, I, D, O, S, C, O, P, E. It's three roots: kalos, beautiful, plus eidos, form, plus scope, look. So it looks at beautiful forms.","show":{"t":"breakdown","word":"kaleidoscope","hi":[7,5],"parts":[{"txt":"kal","gloss":"beautiful"},{"txt":"eido","gloss":"form"},{"txt":"scope","gloss":"look at"}]}},{"mood":"oops","cap":"horoscope — hora = hour, not a body part","say":"One word breaks the pattern. Horoscope uses hora, meaning hour, so it looks at the hour of your birth. The root isn't a body part or a science, just time. A friendly exception.","show":{"t":"word","word":"horoscope","hi":[0,4]}}]},"53":{"label":"Greek log / logy","scenes":[{"mood":"happy","cap":"logos = word, reason, study","say":"Meet the Greek root log, spelled L, O, G. It comes from logos, meaning word, reason, or study. It's one of the busiest roots in all of English.","show":{"t":"glyph","text":"log","sub":"word · reason · study"}},{"mood":"happy","cap":"dia (between) + logue → dialogue","say":"As logue, it means speech or words. Dialogue breaks into dia, meaning between, plus logue, so it's words between two people. Monologue uses mono, one, for one person's long speech.","show":{"t":"breakdown","word":"dialogue","hi":[3,5],"parts":[{"txt":"dia","gloss":"between"},{"txt":"logue","gloss":"words"}]}},{"mood":"happy","cap":"eu (good) + logy → eulogy","say":"It also means good words. Eulogy breaks into eu, meaning good, plus logy, so it's good words spoken about someone, usually at a funeral. A neologism is a brand new word.","show":{"t":"breakdown","word":"eulogy","hi":[2,4],"parts":[{"txt":"eu","gloss":"good"},{"txt":"logy","gloss":"words"}]}},{"mood":"oops","cap":"-agogue (lead) is NOT -logue (speech)","say":"Here's a trap. Demagogue and pedagogue end in agogue, meaning to lead, not logue, meaning speech. A pedagogue leads children, so a teacher. Listen for that extra a-g.","show":{"t":"word","word":"demagogue","hi":[4,5]}},{"mood":"excited","cap":"-log (American) vs -logue (British)","say":"Last, spelling can vary. American English likes catalog and dialog, while British English writes catalogue and dialogue. Scripps uses Merriam-Webster, so lean toward the American spelling.","show":{"t":"list","items":[{"word":"catalog"},{"word":"catalogue"}]}}]},"54":{"label":"Greek phil / phile","scenes":[{"mood":"happy","cap":"philein = to love","say":"Meet the Greek root phil, spelled P, H, I, L. It comes from philein, meaning to love. It sits at the start of words as phil, and at the end as phile.","show":{"t":"glyph","text":"phil","sub":"love"}},{"mood":"happy","cap":"phil + anthropos (human) → philanthropy","say":"At the start, take philanthropy. It breaks into phil, meaning love, plus anthropos, meaning human, so it's love of humanity. Philosophy is phil plus sophia, wisdom, the love of wisdom.","show":{"t":"breakdown","word":"philanthropy","hi":[0,4],"parts":[{"txt":"phil","gloss":"love"},{"txt":"anthrop","gloss":"human"}]}},{"mood":"excited","cap":"biblio (book) + -phile → bibliophile","say":"At the end, phile means one who loves. Bibliophile breaks into biblio, meaning book, plus phile, so it's a book lover. Anglophile loves England, and oenophile loves wine.","show":{"t":"breakdown","word":"bibliophile","hi":[7,4],"parts":[{"txt":"biblio","gloss":"book"},{"txt":"phile","gloss":"one who loves"}]}},{"mood":"happy","cap":"philos (loving) + adelphos (brother)","say":"It even names a city. Philadelphia breaks into philos, meaning loving, plus adelphos, meaning brother. So it's the city of brotherly love, pure Greek living on a map.","show":{"t":"breakdown","word":"philadelphia","hi":[0,4],"parts":[{"txt":"phil","gloss":"loving"},{"txt":"adelph","gloss":"brother"}]}},{"mood":"oops","cap":"always ph, and count the ph's","say":"Spelling rule: it's always p-h, never f. Philanthropy actually has two p-h units, in phil and in anthropos, P, H, I, L, A, N, T, H, R, O, P, Y. Count your Greek p-h's carefully.","show":{"t":"word","word":"philanthropy","hi":[7,2]}}]},"55":{"label":"Greek root gen","scenes":[{"mood":"happy","show":{"t":"glyph","text":"gen","sub":"birth · origin"},"cap":"The root gen means birth or origin.","say":"Meet the root gen, spelled G E N. It comes from Greek, and it means birth, or origin."},{"mood":"excited","show":{"t":"breakdown","word":"oxygen","hi":[3,3],"parts":[{"txt":"oxy","gloss":"sharp, acid"},{"txt":"gen","gloss":"producing"}]},"cap":"oxy (acid) + gen (producing) → oxygen","say":"It loves to hide inside longer words. Take oxygen — oxy means acid, and gen means producing. Oxygen, the gas the scientists thought produced acids."},{"mood":"happy","show":{"t":"breakdown","word":"genre","hi":[0,3],"parts":[{"txt":"gen","gloss":"kind, type"}]},"cap":"genre = a “kind” of art or music","say":"Or genre — built on the same root, meaning a kind, or type, of art or music."},{"mood":"happy","show":{"t":"breakdown","word":"genealogy","hi":[0,3],"parts":[{"txt":"gen","gloss":"birth"},{"txt":"-logy","gloss":"study of"}]},"cap":"gen (birth) + -logy (study) → genealogy","say":"Or genealogy — gen, birth, plus logy, the study of — the study of where a family began."},{"mood":"excited","show":{"t":"glyph","text":"gen","sub":"birth · origin"},"cap":"See G-E-N, think birth — a whole word family opens up.","say":"So whenever you spot G E N, think birth, or origin — and a whole family of words opens right up."}]},"56":{"label":"Greek dem-","scenes":[{"mood":"happy","cap":"Greek demos = people.","say":"Meet the root dem, spelled D, E, M. It comes from Greek demos, and it means people. Every dem word is about people in some way.","show":{"t":"glyph","text":"dem-","sub":"people"}},{"mood":"excited","cap":"democracy = demos + kratos (rule)","say":"Take democracy. Demos means people, plus kratos means rule. So democracy is rule by the people, deciding things together.","show":{"t":"breakdown","word":"democracy","hi":[0,4],"parts":[{"txt":"demo","gloss":"people"},{"txt":"cracy","gloss":"rule"}]}},{"mood":"happy","cap":"epi- (upon) + dem → epidemic","say":"Now diseases. Epidemic adds epi, meaning upon, to dem. It is a sickness upon the people. And pandemic adds pan, meaning all, a sickness across all peoples worldwide.","show":{"t":"breakdown","word":"epidemic","hi":[0,3],"parts":[{"txt":"epi","gloss":"upon"},{"txt":"dem","gloss":"people"}]}},{"mood":"happy","cap":"endemic = en- (within) + dem","say":"And endemic adds en, meaning within. It is a disease that stays within one place, like malaria living in certain tropical regions all the time.","show":{"t":"breakdown","word":"endemic","hi":[0,2],"parts":[{"txt":"en","gloss":"within"},{"txt":"dem","gloss":"people"}]}},{"mood":"oops","cap":"democracy ends -CRACY (not k!), not -kracy","say":"Watch the spelling. Democracy ends C, R, A, C, Y, with a c, never a k. And demagogue ends with a French G, U, E. See D, E, M, think people.","show":{"t":"glyph","text":"-cracy","sub":"c, not k"}}]},"57":{"label":"Latin aud","scenes":[{"mood":"happy","cap":"Latin audire = to hear.","say":"Meet the root aud, spelled A, U, D. It comes from Latin audire, and it means to hear. Everything about listening uses it.","show":{"t":"glyph","text":"aud-","sub":"to hear"}},{"mood":"happy","cap":"audience = those who come to hear","say":"An audience is the people who come to hear. An auditorium is a place for hearing. And audible just means able to be heard.","show":{"t":"breakdown","word":"audible","hi":[0,3],"parts":[{"txt":"aud","gloss":"hear"},{"txt":"ible","gloss":"able to be"}]}},{"mood":"happy","cap":"in- (not) + audible → inaudible","say":"Add the prefix in, meaning not, and you get inaudible, something that cannot be heard at all.","show":{"t":"breakdown","word":"inaudible","hi":[0,2],"parts":[{"txt":"in","gloss":"not"},{"txt":"aud","gloss":"hear"},{"txt":"ible","gloss":"able"}]}},{"mood":"oops","cap":"TRAP: audacious is from audere = to dare!","say":"Here is a famous trap. Audacious starts with the same A, U, D, but it does not mean hearing. It comes from audere, to dare. Same letters, different root, so listen to the meaning.","show":{"t":"breakdown","word":"audacious","hi":[0,3],"parts":[{"txt":"aud","gloss":"from audere: to dare"}]}},{"mood":"excited","cap":"audible = A-U-D-I-B-L-E (-ible)","say":"For spelling, remember audible ends I, B, L, E, not able, because it comes from a Latin stem. When you hear hearing, picture A, U, D.","show":{"t":"glyph","text":"-ible","sub":"Latin stem"}}]},"58":{"label":"Latin dict","scenes":[{"mood":"happy","cap":"Latin dicere = to say.","say":"Meet the root dict, spelled D, I, C, T. It comes from Latin dicere, and it means to say. When something is said officially, dict is usually there.","show":{"t":"glyph","text":"dict","sub":"to say"}},{"mood":"happy","cap":"ver (truth) + dict → verdict","say":"Take verdict. Ver means truth, plus dict means said. A verdict is what is truly said by a jury when they decide.","show":{"t":"breakdown","word":"verdict","hi":[3,4],"parts":[{"txt":"ver","gloss":"truth"},{"txt":"dict","gloss":"said"}]}},{"mood":"excited","cap":"bene (good) + dict vs male (bad) + dict","say":"Here is a neat pair. Benediction is bene, good, plus dict, a good saying, a blessing. Malediction is male, bad, plus dict, a bad saying, a curse. Same root, opposite meanings.","show":{"t":"breakdown","word":"benediction","hi":[0,4],"parts":[{"txt":"bene","gloss":"good"},{"txt":"dict","gloss":"saying"}]}},{"mood":"oops","cap":"indict = silent c, said /in-DYTE/","say":"Watch out for indict. It is spelled I, N, D, I, C, T, but the c is silent, so it sounds like in dite. It still means to formally say a charge against someone.","show":{"t":"word","word":"indict","hi":[3,1]}},{"mood":"happy","cap":"dict is always D-I-C-T","say":"The good news is dict is always spelled D, I, C, T, in predict, contradict, and jurisdiction. Spot it, and think said.","show":{"t":"list","items":[{"word":"predict","hi":[3,4]},{"word":"contradict","hi":[6,4]}]}}]},"59":{"label":"Latin duc / duct","scenes":[{"mood":"happy","cap":"Latin ducere = to lead.","say":"Meet the root duc, spelled D, U, C. It comes from Latin ducere, and it means to lead. It also shows up as duct.","show":{"t":"glyph","text":"duc · duct","sub":"to lead"}},{"mood":"excited","cap":"e- (out) + duc → educate","say":"Take educate. The e means out, plus duc means lead. To educate is to lead knowledge outward from within a person.","show":{"t":"breakdown","word":"educate","hi":[1,3],"parts":[{"txt":"e","gloss":"out"},{"txt":"duc","gloss":"lead"}]}},{"mood":"happy","cap":"Each prefix changes the direction of leading","say":"The prefix sets the direction. Abduct uses ab, away, to lead away by force. Seduce uses se, aside, to lead aside. And reduce uses re, back, to lead back and make smaller.","show":{"t":"breakdown","word":"abduct","hi":[0,2],"parts":[{"txt":"ab","gloss":"away"},{"txt":"duct","gloss":"lead"}]}},{"mood":"happy","cap":"aqua (water) + duct → aqueduct","say":"Compounds are fun too. An aqueduct is aqua, water, plus duct, a structure that leads water along. A duke, from dux, is literally a leader.","show":{"t":"breakdown","word":"aqueduct","hi":[4,4],"parts":[{"txt":"aque","gloss":"water"},{"txt":"duct","gloss":"lead"}]}},{"mood":"oops","cap":"duc before vowels, duct before consonants","say":"For spelling, the root is duc before vowels, as in reduce and educate, but duct before consonants, as in conduct and abduct. Same root, two shapes.","show":{"t":"glyph","text":"duc / duct","sub":"vowel vs consonant"}}]},"60":{"label":"Latin fer","scenes":[{"mood":"happy","cap":"Latin ferre = to carry, to bear.","say":"Meet the root fer, spelled F, E, R. It comes from Latin ferre, and it means to carry, or to bear.","show":{"t":"glyph","text":"fer","sub":"carry · bear"}},{"mood":"happy","cap":"trans (across) + fer → transfer","say":"Take transfer. Trans means across, plus fer means carry, so to transfer is to carry something across. And prefer uses pre, before, to carry one thing before others.","show":{"t":"breakdown","word":"transfer","hi":[5,3],"parts":[{"txt":"trans","gloss":"across"},{"txt":"fer","gloss":"carry"}]}},{"mood":"excited","cap":"conus (cone) + -fer → conifer","say":"Science loves fer. A conifer carries cones, so it is a cone bearing tree. An aquifer carries water underground. Whatever the word bears, fer is doing the carrying.","show":{"t":"breakdown","word":"conifer","hi":[4,3],"parts":[{"txt":"coni","gloss":"cone"},{"txt":"fer","gloss":"bearing"}]}},{"mood":"happy","cap":"sub (under) + ferre → suffer","say":"Even suffer hides fer. Sub means under and ferre means carry, so to suffer is to carry something under, to endure it.","show":{"t":"breakdown","word":"suffer","hi":[3,3],"parts":[{"txt":"suf","gloss":"under"},{"txt":"fer","gloss":"carry"}]}},{"mood":"oops","cap":"prefer → preferring (double r when stress shifts)","say":"Spelling trap. When stress lands on the fer, you double the r. Prefer becomes preferring, and refer becomes referred. But offer keeps one r, because its stress is up front.","show":{"t":"glyph","text":"-ferr-","sub":"double r when stressed"}}]},"61":{"label":"Latin scrib/script","scenes":[{"mood":"happy","cap":"Latin scribere = to write.","say":"Meet the root scrib, spelled S, C, R, I, B. It comes from Latin scribere, and it means to write. It also appears as script.","show":{"t":"glyph","text":"scrib · script","sub":"to write"}},{"mood":"happy","cap":"manus (hand) + script → manuscript","say":"Take manuscript. Manus means hand, plus script means written. A manuscript is something written by hand.","show":{"t":"breakdown","word":"manuscript","hi":[5,5],"parts":[{"txt":"manu","gloss":"hand"},{"txt":"script","gloss":"written"}]}},{"mood":"happy","cap":"in (on) + scribe → inscribe","say":"Prefixes add direction. To inscribe is to write on or into a surface. To subscribe uses sub, under, to write your name underneath and agree to something.","show":{"t":"breakdown","word":"subscribe","hi":[3,6],"parts":[{"txt":"sub","gloss":"under"},{"txt":"scribe","gloss":"write"}]}},{"mood":"oops","cap":"TRAP: prescribe vs proscribe","say":"Careful with two look alikes. Prescribe, with pre, means to write out in advance, like a doctor. Proscribe, with pro, means to publicly ban. One letter changes everything.","show":{"t":"list","items":[{"word":"prescribe","hi":[0,3]},{"word":"proscribe","hi":[0,3]}]}},{"mood":"excited","cap":"scrib before vowels, script before consonants","say":"For spelling, use scrib before vowels, as in describe, and script before consonants, as in inscription. Keep that S, C cluster together and you will write them right.","show":{"t":"glyph","text":"-sc-","sub":"keep s and c together"}}]},"62":{"label":"Latin port","scenes":[{"mood":"happy","cap":"Latin portare = to carry.","say":"Meet the root port, spelled P, O, R, T. It comes from Latin portare, and it means to carry. Every port word moves something.","show":{"t":"glyph","text":"port","sub":"to carry"}},{"mood":"excited","cap":"im- (in) + port vs ex- (out) + port","say":"Trade words show it best. Import uses in, to carry goods into a country, and export uses ex, out, to carry goods out. Transport uses trans, across, to carry across.","show":{"t":"list","items":[{"word":"import","hi":[0,2]},{"word":"export","hi":[0,2]}]}},{"mood":"happy","cap":"sub (under) + port → support","say":"Even feelings can be carried. Support uses sub, from under, to carry something up and hold it. Report uses re, back, to carry news back to you.","show":{"t":"breakdown","word":"support","hi":[3,4],"parts":[{"txt":"sup","gloss":"from under"},{"txt":"port","gloss":"carry"}]}},{"mood":"love","cap":"deportment = how you carry yourself","say":"I love this one. Deportment is de, plus port, plus ment, and it means the way you carry yourself, your posture and manner. You literally carry yourself around.","show":{"t":"breakdown","word":"deportment","hi":[2,4],"parts":[{"txt":"de","gloss":""},{"txt":"port","gloss":"carry"},{"txt":"ment","gloss":"state"}]}},{"mood":"oops","cap":"rapport = R-A-P-P-O-R-T, silent final t","say":"Sneaky spelling. Rapport hides the port root through French. It has a double p and a silent final t, spelled R, A, P, P, O, R, T. The carry meaning is buried inside.","show":{"t":"word","word":"rapport","hi":[6,1]}}]},"63":{"label":"Latin miss / mit","scenes":[{"mood":"happy","cap":"Latin mittere = to send.","say":"Meet the root from Latin mittere, meaning to send. It wears two faces. The verb form is mit, spelled M, I, T, and the noun form is miss, spelled M, I, S, S.","show":{"t":"glyph","text":"miss · mit","sub":"to send"}},{"mood":"happy","cap":"e- (out) + mit → emit","say":"Verbs use mit. Emit uses e, out, to send out. Submit uses sub, under, to send yourself under someone's authority. Transmit uses trans, across, to send across.","show":{"t":"breakdown","word":"emit","hi":[1,3],"parts":[{"txt":"e","gloss":"out"},{"txt":"mit","gloss":"send"}]}},{"mood":"excited","cap":"per (through) + mission → permission","say":"Now the noun side flips to miss. Permission is per, through, plus mission, a sending through, official allowance. Intermission is a sending between acts, a break.","show":{"t":"breakdown","word":"permission","hi":[3,7],"parts":[{"txt":"per","gloss":"through"},{"txt":"mission","gloss":"a sending"}]}},{"mood":"happy","cap":"missile = something sent","say":"Even a missile is just something sent flying, and a message is something sent to you. All from mittere, to send.","show":{"t":"word","word":"missile","hi":[0,4]}},{"mood":"oops","cap":"verb = -mit; noun = -mission; double t when stressed","say":"Spelling rule. Verbs end M, I, T, and nouns end M, I, S, S, I, O, N. And when you stress the mit, double the t. Commit becomes committed.","show":{"t":"glyph","text":"committed","sub":"double t when stressed"}}]},"64":{"label":"Latin vert / vers","scenes":[{"mood":"happy","cap":"Latin vertere = to turn.","say":"Meet the root from Latin vertere, meaning to turn. As a verb it is vert, spelled V, E, R, T, and as a noun it becomes vers, spelled V, E, R, S.","show":{"t":"glyph","text":"vert · vers","sub":"to turn"}},{"mood":"happy","cap":"in (into) + vert → invert","say":"Take invert. In means into, plus vert means turn, so to invert is to turn something inside out. Revert uses re, back, to turn back to how it was.","show":{"t":"breakdown","word":"invert","hi":[2,4],"parts":[{"txt":"in","gloss":"into"},{"txt":"vert","gloss":"turn"}]}},{"mood":"excited","cap":"intro (inward) + vert → introvert","say":"Personality words use it. An introvert turns inward, with intro meaning inward, while an extrovert turns outward. Same root, opposite directions.","show":{"t":"breakdown","word":"introvert","hi":[5,4],"parts":[{"txt":"intro","gloss":"inward"},{"txt":"vert","gloss":"turn"}]}},{"mood":"love","cap":"annus (year) + vers (turning) → anniversary","say":"Here is a lovely one. Anniversary is annus, year, plus vers, turning, plus ary. It is the turning of the year coming back around. Versatile means able to turn to many tasks.","show":{"t":"breakdown","word":"anniversary","hi":[5,4],"parts":[{"txt":"anni","gloss":"year"},{"txt":"vers","gloss":"turning"}]}},{"mood":"oops","cap":"verb -vert; noun -version; anniversary double n","say":"Spelling check. Verbs use vert, like convert, and nouns use version, like conversion. And anniversary has a double n, from annus, year, spelled A, N, N.","show":{"t":"glyph","text":"anniversary","sub":"double n"}}]},"65":{"label":"Latin spec/spect","scenes":[{"mood":"happy","cap":"Latin specere = to look.","say":"Meet the root spec, spelled S, P, E, C. It comes from Latin specere, and it means to look. It also appears as spect, and the rarer spic.","show":{"t":"glyph","text":"spec · spect","sub":"to look"}},{"mood":"happy","cap":"pro (forward) + spect → prospect","say":"Direction comes from the prefix. Prospect uses pro, forward, looking forward to the future. Retrospect uses retro, backward, looking back. Inspect means to look into.","show":{"t":"breakdown","word":"prospect","hi":[3,5],"parts":[{"txt":"pro","gloss":"forward"},{"txt":"spect","gloss":"look"}]}},{"mood":"happy","cap":"circum (around) + spect → circumspect","say":"Circumspect uses circum, around. It means looking carefully all around you, so it describes a cautious person.","show":{"t":"breakdown","word":"circumspect","hi":[6,5],"parts":[{"txt":"circum","gloss":"around"},{"txt":"spect","gloss":"look"}]}},{"mood":"excited","cap":"con + spic → conspicuous","say":"Now the tricky spic form. Conspicuous, looked at together, means easy to see. Perspicacious, using per, through, means looking right through a problem, sharply insightful.","show":{"t":"breakdown","word":"conspicuous","hi":[3,4],"parts":[{"txt":"con","gloss":"together"},{"txt":"spic","gloss":"look"}]}},{"mood":"oops","cap":"watch the -spic- cluster: S-P-I-C","say":"Spelling trap. In words like conspicuous and auspicious, the look root is spic, spelled S, P, I, C, not spec. That little spic cluster is the part that trips people up.","show":{"t":"glyph","text":"-spic-","sub":"S-P-I-C, not spec"}}]},"66":{"label":"Latin ten/tain/tent","scenes":[{"mood":"happy","cap":"Latin tenere = to hold.","say":"Meet the root from Latin tenere, meaning to hold. It wears three coats. Ten, spelled T, E, N, plus tain, T, A, I, N, plus tent, T, E, N, T.","show":{"t":"glyph","text":"ten·tain·tent","sub":"to hold"}},{"mood":"happy","cap":"de (away) + tain → detain","say":"The tain form takes prefixes. Detain uses de, away, to hold someone away from going. Retain uses re, back, to hold back and keep. Contain uses con, together, to hold together.","show":{"t":"breakdown","word":"detain","hi":[2,4],"parts":[{"txt":"de","gloss":"away"},{"txt":"tain","gloss":"hold"}]}},{"mood":"happy","cap":"at (toward) + tent → attention","say":"The tent form holds too. Attention is held toward something, with ad meaning toward. Detention is the state of being held, kept from leaving.","show":{"t":"breakdown","word":"attention","hi":[2,4],"parts":[{"txt":"at","gloss":"toward"},{"txt":"tent","gloss":"hold"}]}},{"mood":"love","cap":"tenacious = holding on firmly","say":"My favorite is tenacious, from tenax, holding on firmly. A tenacious person holds tight and never gives up. A tenant simply holds a property.","show":{"t":"breakdown","word":"tenacious","hi":[0,3],"parts":[{"txt":"ten","gloss":"hold"},{"txt":"acious","gloss":"full of"}]}},{"mood":"oops","cap":"abstain = A-B-S-T-A-I-N (-ai- pair)","say":"Spelling watch. The tain form uses the vowel pair A, I, as in abstain, spelled A, B, S, T, A, I, N. Three coats, one idea, always holding.","show":{"t":"glyph","text":"-tain","sub":"a, i vowel pair"}}]},"67":{"label":"Latin cred","scenes":[{"mood":"happy","cap":"Latin credere = to believe.","say":"Meet the root cred, spelled C, R, E, D. It comes from Latin credere, and it means to believe. It is all about trust and faith.","show":{"t":"glyph","text":"cred","sub":"to believe"}},{"mood":"happy","cap":"in- (not) + credible → incredible","say":"Add prefixes and meanings flip. Credible means believable, but incredible uses in, not, so it means too amazing to believe. Discredit removes someone's believability.","show":{"t":"breakdown","word":"incredible","hi":[0,2],"parts":[{"txt":"in","gloss":"not"},{"txt":"cred","gloss":"believe"},{"txt":"ible","gloss":"able"}]}},{"mood":"happy","cap":"creed = a statement of beliefs","say":"A creed is what you believe, a statement of beliefs. Credentials are proof that makes you believable, your qualifications. Even credit is trust given before you pay back.","show":{"t":"word","word":"creed","hi":[0,4]}},{"mood":"excited","cap":"mis (wrongly) + cred → miscreant","say":"Here is a dark corner. Miscreant is mis, wrongly, plus cred, believe, plus ant. It once meant one who believes wrongly, and now it just means a villain.","show":{"t":"breakdown","word":"miscreant","hi":[3,4],"parts":[{"txt":"mis","gloss":"wrongly"},{"txt":"cre","gloss":"believe"},{"txt":"ant","gloss":"one who"}]}},{"mood":"oops","cap":"incredulous = -ULOUS; miscreant = -EAN-","say":"Two spelling traps. Incredulous ends U, L, O, U, S, not ious. And miscreant has E, A, N in the middle, not double e. Hear believe, and write C, R, E, D.","show":{"t":"glyph","text":"-ulous","sub":"not -ious"}}]},"68":{"label":"Silent kn/gn/wr","scenes":[{"mood":"happy","cap":"Old English & Norse silent first letters","say":"Some words start with two consonants, but you only hear the second one. These come from Old English and Norse, where the first letter was once spoken, then went silent.","show":{"t":"glyph","text":"kn · gn · wr","sub":"silent first letter"}},{"mood":"happy","cap":"wr- = silent w, only the r is heard","say":"First, the W, R cluster. In wraith, a ghost, and wrath, fury, and wring, to twist tightly, the w is silent. You only hear the r.","show":{"t":"list","items":[{"word":"wraith","hi":[0,2]},{"word":"wrath","hi":[0,2]}]}},{"mood":"happy","cap":"kn- = silent k (German Knabe, Knie)","say":"Next, the K, N cluster, from Old Norse. In knight and kneel and knot, the k is silent. You can still hear it in German Knabe, meaning boy.","show":{"t":"list","items":[{"word":"knight","hi":[0,2]},{"word":"kneel","hi":[0,2]}]}},{"mood":"love","cap":"gn- = silent g (Italian gnocchi)","say":"Then the G, N cluster. In gnome and gnaw and gnarled, twisted, the g is silent. You can still hear it in the Italian word gnocchi.","show":{"t":"list","items":[{"word":"gnome","hi":[0,2]},{"word":"gnaw","hi":[0,2]}]}},{"mood":"excited","cap":"Hear /r/ or /n/? Ask the origin!","say":"Bee tip. If you hear an r sound on an old, literary word, think w, r. If you hear an n sound on a medieval word, think k, n. The silent letter is hiding up front.","show":{"t":"glyph","text":"kn·gn·wr","sub":"listen for the hidden letter"}}]},"69":{"label":"Silent -gh-","scenes":[{"mood":"happy","cap":"-gh- once = a guttural /kh/ sound","say":"The cluster G, H is Old English's trickiest leftover. It once sounded like a rough kh, like in the German name Bach. That sound vanished, but the letters stayed.","show":{"t":"glyph","text":"-gh-","sub":"once a /kh/ sound"}},{"mood":"happy","cap":"-igh- always = the /eye/ sound","say":"The most regular pattern is i, g, h. In night and right and bright, the letters I, G, H always make the eye sound, and the g, h is completely silent.","show":{"t":"list","items":[{"word":"night","hi":[1,3]},{"word":"bright","hi":[2,3]}]}},{"mood":"happy","cap":"-aught = the /awt/ sound","say":"Another steady group is a, u, g, h, t. In daughter and caught and fraught, meaning full of worry, those letters say awt. This group is very consistent.","show":{"t":"list","items":[{"word":"daughter","hi":[1,4]},{"word":"fraught","hi":[2,4]}]}},{"mood":"oops","cap":"-ough = SIX different sounds!","say":"Now the wild one, o, u, g, h. It has six different sounds. Though rhymes with go, through with too, rough with stuff, and thought with awt. Learn them by sound, in groups.","show":{"t":"list","items":[{"word":"though","hi":[2,4]},{"word":"rough","hi":[1,4]}]}},{"mood":"excited","cap":"Ask origin + definition to choose","say":"Bee tip. Always ask for the origin and meaning. An Old English word with an awt sound points to a, u, g, h, t. With an eye sound, it points to i, g, h, t.","show":{"t":"glyph","text":"origin?","sub":"it picks the pattern"}}]},"70":{"label":"i before e rule","scenes":[{"mood":"happy","cap":"\"i before e, except after c...\"","say":"Here's the famous rhyme: i before e, spelled I before E, except after c. After most consonants, ie sounds like ee, as in believe and achieve.","show":{"t":"glyph","text":"ie → /ee/","sub":"i before e"}},{"mood":"happy","cap":"After c, the order flips → ei","say":"But after the letter c, the order flips. The c is selfish and pushes e in front of i. So we get ceiling, and receive, and deceive.","show":{"t":"list","items":[{"word":"ceiling","hi":[1,2]},{"word":"receive","hi":[3,2]}]}},{"mood":"happy","cap":"When it sounds like /ay/ → ei","say":"There's one more: when the letters sound like ay, e comes before i. Think of vein, and reign, and feign. The ay sound overrides the normal order.","show":{"t":"word","word":"reign","hi":[1,2]}},{"mood":"oops","cap":"Watch out: seize, weird, height","say":"Now watch out! Some words just break the rule and must be memorized. Seize, weird, and height all sneak an e in front of an i with no c to blame.","show":{"t":"list","items":[{"word":"seize","hi":[1,2]},{"word":"weird","hi":[1,2]},{"word":"height","hi":[2,2]}]}},{"mood":"excited","cap":"The rule covers 80% — memorize the rest.","say":"So lean on the rhyme: i before e, except after c, or when it sounds like ay. It catches most words, and the strange leftovers you simply learn by heart.","show":{"t":"glyph","text":"ie · cei · ei","sub":"three patterns"}}]},"71":{"label":"Doubling consonants","scenes":[{"mood":"happy","cap":"CVC + vowel suffix → double the last letter","say":"When do you double a final consonant before an ending like ing or ed? For a one-syllable word that ends consonant, vowel, consonant, you double it. Run becomes running.","show":{"t":"glyph","text":"run → running","sub":"double keeps it short"}},{"mood":"oops","cap":"Without the double, the vowel goes long.","say":"Why bother? The double keeps the vowel short. Without it, runing would rhyme with tuning! So stop becomes stopped, and sit becomes sitting.","show":{"t":"list","items":[{"word":"stopped","hi":[3,2]},{"word":"sitting","hi":[2,2]}]}},{"mood":"excited","cap":"Two syllables? Stress is the key.","say":"Here's the clever part for two-syllable words: double only if the stress lands on the last syllable. Begin is stressed at the end, so we get beginning with a double n.","show":{"t":"breakdown","word":"beginning","hi":[5,2],"parts":[{"txt":"be-GIN","gloss":"stress at end"},{"txt":"-ning","gloss":"double n"}]}},{"mood":"happy","cap":"Stress on the first syllable → no double","say":"Tap the syllables and feel which is louder. Occur is oc-CUR, louder at the end, so occurred doubles the r. But open is OP-en, louder at the front, so opening stays single.","show":{"t":"list","items":[{"word":"occurred","hi":[4,2]},{"word":"preferred","hi":[5,2]}]}},{"mood":"oops","cap":"Some doubles you just memorize.","say":"And a few words keep doubles for no suffix reason at all. Embarrass has a double r and a double s. Millennium has double l and double n. Those you simply memorize.","show":{"t":"word","word":"embarrass","hi":[4,2]}}]},"72":{"label":"Soft c = /s/","scenes":[{"mood":"happy","cap":"c = /k/ before a, o, u — /s/ before e, i, y","say":"The letter c has two voices. It says k before a, o, and u, as in cat and cup. But it softens to an s before e, i, and y, as in city and cell.","show":{"t":"glyph","text":"c → /s/","sub":"before e, i, y"}},{"mood":"excited","cap":"The vowel after c picks the sound — every time.","say":"So the vowel that follows c decides everything. Cell starts with s and call starts with k, same letter, different vowel behind it. Once you know this, you can decode brand-new words.","show":{"t":"list","items":[{"word":"cell","hi":[0,1]},{"word":"call","hi":[0,1]}]}},{"mood":"happy","cap":"-sc- before e/i also = /s/","say":"There's a sneaky cluster too. The letters s c together, before e or i, also make an s sound, as in effervescent and luminescent. The s is redundant, but you must spell both letters.","show":{"t":"breakdown","word":"effervescent","hi":[7,2],"parts":[{"txt":"-sc-","gloss":"still /s/ before e"}]}},{"mood":"happy","cap":"-ci- becomes /sh/ in suffixes","say":"And c before i can soften further to a sh sound in endings. Luscious, precious, and spacious all hide a c before i making that shushing sound.","show":{"t":"list","items":[{"word":"precious","hi":[3,2]},{"word":"spacious","hi":[3,2]}]}},{"mood":"oops","cap":"susceptible, not susceptable","say":"Watch the trap word susceptible. The c before e keeps it soft, and it ends i-b-l-e, not a-b-l-e. Remember the c chose e, and you'll spell it right.","show":{"t":"word","word":"susceptible","hi":[3,2]}}]},"73":{"label":"Greek ph = /f/","scenes":[{"mood":"happy","cap":"ph = /f/ signals Greek origin","say":"When you hear an f sound in a fancy, scientific, or bookish word, reach for p h, not f. That p h is the Greek letter phi, and it traveled into English with Greek words.","show":{"t":"glyph","text":"ph → /f/","sub":"Greek signal"}},{"mood":"oops","cap":"Everyday words use plain f.","say":"But careful, everyday words you knew as a tiny kid use a plain f. Fun, fish, and fog are all simple f. The p h trick only applies to learned, borrowed words.","show":{"t":"list","items":[{"word":"fish","hi":[0,1]},{"word":"fog","hi":[0,1]}]}},{"mood":"happy","cap":"phenomenon, metaphor, ephemeral","say":"Listen for it in phenomenon, a thing observed. In metaphor, a figure of speech. In ephemeral, lasting a very short time. Every f sound there is really a p h.","show":{"t":"list","items":[{"word":"metaphor","hi":[5,2]},{"word":"ephemeral","hi":[1,2]}]}},{"mood":"excited","cap":"diphthong = di + phthongos (two sounds)","say":"The hardest one is diphthong, a gliding speech sound. Break it: di, meaning two, plus phthongos, meaning sound. That gives the brutal p h t h cluster in the middle.","show":{"t":"breakdown","word":"diphthong","hi":[2,4],"parts":[{"txt":"di-","gloss":"two"},{"txt":"phthongos","gloss":"sound"}]}},{"mood":"excited","cap":"Hear /f/ in a learned word → write ph.","say":"So whenever a clever word hisses an f at you, picture the Greek phi. Phosphorus, sycophant, ophthalmology, all spelled with that telltale p h.","show":{"t":"glyph","text":"ph","sub":"/f/ · Greek"}}]},"74":{"label":"qu combination","scenes":[{"mood":"happy","cap":"q almost always brings a u","say":"In English, the letter q is almost never alone. It nearly always drags a u right behind it. Together, q u usually says kw, as in queen and question.","show":{"t":"glyph","text":"qu → /kw/","sub":"q needs its u"}},{"mood":"excited","cap":"French -que → /k/, not /kw/","say":"But here's a twist. In French words ending q-u-e, the q u softens to just k. Bouquet, clique, and opaque all end in that quiet que sound.","show":{"t":"list","items":[{"word":"clique","hi":[3,3]},{"word":"opaque","hi":[3,3]}]}},{"mood":"happy","cap":"eloquent = e + loqui (speak)","say":"In Latin words, q u stays as kw. Take eloquent: e, plus loqui, meaning to speak. An eloquent person speaks readily and clearly.","show":{"t":"breakdown","word":"eloquent","hi":[3,2],"parts":[{"txt":"e-","gloss":"out"},{"txt":"loqui","gloss":"to speak"}]}},{"mood":"happy","cap":"soliloquy = speaking alone","say":"And soliloquy, a speech to yourself, keeps the kw too. Spell it s-o-l-i-l-o-q-u-y. The q still needs its u, and then a vowel, here a y, finishes the syllable.","show":{"t":"word","word":"soliloquy","hi":[5,3]}},{"mood":"oops","cap":"Rare q-without-u words: qi, qanat","say":"Watch out for rare borrowed words where q has no u at all, like qi or qanat. At a bee, just ask for the origin to catch those tricky ones.","show":{"t":"glyph","text":"qi · qanat","sub":"q with no u"}}]},"75":{"label":"Greek y vowel","scenes":[{"mood":"happy","cap":"y in the middle = a vowel (Greek)","say":"Usually y is a sidekick, but in Greek words it works as a full vowel. When you spot a y in the middle of a word, it's often Greek, sounding like i or uh.","show":{"t":"glyph","text":"y","sub":"Greek vowel"}},{"mood":"excited","cap":"It came from Greek upsilon (Υ).","say":"This y is the Greek letter upsilon. The Romans had no upsilon, so they wrote y instead, and English inherited that habit. So a middle y is a little fossil of Greek.","show":{"t":"word","word":"rhythm","hi":[2,1]}},{"mood":"happy","cap":"y as the only vowel: crypt, lymph, nymph","say":"Sometimes y is the only vowel in the word. Crypt, a hidden vault. Lymph, a body fluid. Nymph, a nature goddess. In each, that lonely y carries the whole vowel sound.","show":{"t":"list","items":[{"word":"crypt","hi":[3,1]},{"word":"nymph","hi":[1,1]}]}},{"mood":"happy","cap":"Greek y clusters: syn-, sym-, -yp-","say":"Watch for Greek clusters with y. We get s-y-n in synonym, s-y-m in symbol, and y again in oxygen and labyrinth. The y keeps showing up where Greek went.","show":{"t":"list","items":[{"word":"symbol","hi":[1,1]},{"word":"oxygen","hi":[3,1]}]}},{"mood":"excited","cap":"Middle y → think Greek, spell the y.","say":"So when a vowel sound sits in the middle of a learned word, picture a y. Gymnasium, typhoon, syllable, all proudly Greek, all spelled with that upsilon y.","show":{"t":"glyph","text":"y","sub":"Greek inside"}}]},"76":{"label":"-ough sounds","scenes":[{"mood":"happy","cap":"-ough = one spelling, six sounds","say":"Meet the wildest spelling in English: o-u-g-h. Four letters, but they make six totally different sounds, with no rule to tell you which. You learn them by groups.","show":{"t":"glyph","text":"-ough","sub":"six sounds!"}},{"mood":"happy","cap":"Group /oh/: though, dough, furlough","say":"First group sounds like oh, rhyming with go. Though, dough, and furlough all end in o-u-g-h but glide out on an oh sound.","show":{"t":"list","items":[{"word":"though","hi":[2,4]},{"word":"dough","hi":[1,4]}]}},{"mood":"oops","cap":"Group /uf/: rough, tough, enough","say":"Now it gets sneaky. The same o-u-g-h can say uff, rhyming with stuff. Rough, tough, and enough, but through says oo! Same letters, wildly different sounds.","show":{"t":"list","items":[{"word":"rough","hi":[1,4]},{"word":"tough","hi":[1,4]}]}},{"mood":"happy","cap":"Group /aw/: thought, bought, fought","say":"The biggest group sounds like aw, rhyming with law. Thought, bought, fought, and distraught all share that aw sound under the o-u-g-h.","show":{"t":"list","items":[{"word":"thought","hi":[2,4]},{"word":"bought","hi":[1,4]}]}},{"mood":"excited","cap":"Always spell the silent gh!","say":"Here's the one rule you can trust: the g h is always there, and always silent. When you hear one of these words, ask for the meaning, then spell that quiet g h with confidence.","show":{"t":"glyph","text":"gh","sub":"silent but spelled"}}]},"77":{"label":"Medical roots","scenes":[{"mood":"happy","cap":"body-part root + suffix = medical word","say":"Medical words look scary but follow one tidy recipe. Take a body-part root, add a suffix for what's happening, and you've built a medical term. Learn the parts, decode anything.","show":{"t":"glyph","text":"root + suffix","sub":"medical recipe"}},{"mood":"excited","cap":"cardio = heart","say":"Cardio means heart. So cardiovascular is heart plus blood vessels. And myocardial adds myo, meaning muscle, to give us the heart muscle.","show":{"t":"breakdown","word":"myocardial","hi":[2,6],"parts":[{"txt":"myo-","gloss":"muscle"},{"txt":"cardi-","gloss":"heart"}]}},{"mood":"happy","cap":"neuro = nerve, -itis = inflammation","say":"Neuro means nerve, as in neurological. And the suffix i-t-i-s always means inflammation. So encephalitis, with encephalo meaning brain, is brain inflammation.","show":{"t":"breakdown","word":"encephalitis","hi":[9,4],"parts":[{"txt":"encephalo-","gloss":"brain"},{"txt":"-itis","gloss":"inflammation"}]}},{"mood":"happy","cap":"gastro = stomach + -logy = study","say":"Gastro means stomach. Add entero for intestine and logy for the study of, and gastroenterology is simply the study of the digestive system.","show":{"t":"breakdown","word":"gastroenterology","hi":[0,6],"parts":[{"txt":"gastro-","gloss":"stomach"},{"txt":"-logy","gloss":"study of"}]}},{"mood":"oops","cap":"Silent p in pneumonia!","say":"One trap: pneumonia, lung inflammation, hides a silent p at the very front. Spell it p-n-e-u-m-o-n-i-a. See the part plus the suffix, and any medical word unlocks.","show":{"t":"word","word":"pneumonia","hi":[0,1]}}]},"78":{"label":"Science roots","scenes":[{"mood":"happy","cap":"Science words = roots stacked together","say":"Long science words aren't random. They're built from Greek and Latin roots stacked together, each spelled by its own rules. Know the roots, and the words spell themselves.","show":{"t":"glyph","text":"root + root","sub":"science recipe"}},{"mood":"excited","cap":"photosynthesis = light + together + placing","say":"Take photosynthesis: photo, meaning light, plus synthesis, meaning placing together. Plants placing light together to make food. Five Greek parts, all spelled predictably.","show":{"t":"breakdown","word":"photosynthesis","hi":[0,5],"parts":[{"txt":"photo-","gloss":"light"},{"txt":"synthesis","gloss":"placing together"}]}},{"mood":"happy","cap":"electrolysis = electro + lysis (breaking)","say":"In chemistry, lysis means breaking. So electrolysis is breaking chemical bonds with electricity. The same lysis sits inside catalysis too.","show":{"t":"breakdown","word":"electrolysis","hi":[7,5],"parts":[{"txt":"electro-","gloss":"electricity"},{"txt":"lysis","gloss":"breaking"}]}},{"mood":"love","cap":"centrifugal flees, centripetal seeks","say":"Here's a lovely pair of opposites. Centrifugal uses fuga, to flee, so it flees from the center. Centripetal uses petere, to seek, so it seeks the center.","show":{"t":"list","items":[{"word":"centrifugal","hi":[6,3]},{"word":"centripetal","hi":[6,3]}]}},{"mood":"oops","cap":"stoichiometry = stoikheion + -metry","say":"The trickiest is stoichiometry. Break it: stoikheion, meaning element, plus metry, meaning measuring. Measuring chemical proportions. Spell it s-t-o-i-c-h-i-o, then metry.","show":{"t":"breakdown","word":"stoichiometry","hi":[0,8],"parts":[{"txt":"stoikheion","gloss":"element"},{"txt":"-metry","gloss":"measuring"}]}}]},"79":{"label":"Arts vocabulary","scenes":[{"mood":"happy","cap":"Arts words: Italian, French, Greek","say":"Arts words come from three places. Italian rules music, French rules dance and visual art, and Greek rules theory. Spot the language, and you've guessed the spelling.","show":{"t":"glyph","text":"IT · FR · GR","sub":"three sources"}},{"mood":"happy","cap":"arabesque = Arab + -esque (in the style of)","say":"French dance gives us arabesque, a ballet pose. Break it: Arab, plus the ending e-s-q-u-e, meaning in the style of. So arabesque means in the Arabic style.","show":{"t":"breakdown","word":"arabesque","hi":[4,5],"parts":[{"txt":"Arab","gloss":"Arabic"},{"txt":"-esque","gloss":"in the style of"}]}},{"mood":"oops","cap":"pirouette: -ou-, double t, silent e","say":"Watch pirouette, a spinning turn on one foot. It packs the French o-u, a double t, and a silent e at the end. Spell it p-i-r-o-u-e-t-t-e.","show":{"t":"word","word":"pirouette","hi":[3,2]}},{"mood":"excited","cap":"syncopation = syn + koptein (cut)","say":"Greek music theory gives syncopation, putting the beat where you don't expect it. Break it: syn, meaning together, plus koptein, meaning to cut. The rhythm gets cut and shifted.","show":{"t":"breakdown","word":"syncopation","hi":[0,3],"parts":[{"txt":"syn-","gloss":"together"},{"txt":"koptein","gloss":"to cut"}]}},{"mood":"happy","cap":"cadenza = from cadere (to fall)","say":"And from Italian, a cadenza is a brilliant solo near the end of a piece. It comes from cadere, meaning to fall, the music falling toward its close.","show":{"t":"breakdown","word":"cadenza","hi":[0,4],"parts":[{"txt":"cadere","gloss":"to fall"}]}}]},"80":{"label":"Culinary words","scenes":[{"mood":"happy","cap":"Food words follow their home language","say":"The kitchen is international. French rules the professional terms, Italian brings pasta and cheese words, and each language carries its own spelling signals.","show":{"t":"glyph","text":"FR · IT · JP","sub":"global kitchen"}},{"mood":"oops","cap":"roux = R-O-U-X, silent x","say":"French gives us roux, a flour and butter base, named for its reddish-brown color. Spell it r-o-u-x, and yes, that final x is totally silent.","show":{"t":"word","word":"roux","hi":[3,1]}},{"mood":"happy","cap":"mirepoix: -oi- = /wah/ (French)","say":"Mirepoix is the diced onion, celery, and carrot base. Notice the French o-i, which sounds like wah. So it's meer-pwah, ending in p-o-i-x.","show":{"t":"word","word":"mirepoix","hi":[4,2]}},{"mood":"excited","cap":"Italian -sch- = /sk/, -sci- = /sh/","say":"Italian flips the clusters. In bruschetta, s-c-h says sk, so it's broo-sketta. But in prosciutto, s-c-i says sh, so it's pro-shoot-toh. Same letters, opposite sounds!","show":{"t":"list","items":[{"word":"bruschetta","hi":[3,3]},{"word":"prosciutto","hi":[3,3]}]}},{"mood":"oops","cap":"saffron: double f from Arabic za'faran","say":"And a spice trap: saffron, the purple-crocus spice, comes from the Arabic za'faran. Remember its double f. Spell it s-a-f-f-r-o-n.","show":{"t":"word","word":"saffron","hi":[2,2]}}]},"81":{"label":"Geography words","scenes":[{"mood":"happy","cap":"Place words come from many languages","say":"Geography words borrow widely: Greek for landforms, Spanish and Portuguese for the Americas, and Old Norse for the far north. The origin hints at the spelling.","show":{"t":"glyph","text":"GR · ES · NO","sub":"many origins"}},{"mood":"excited","cap":"peninsula = paene + insula (almost an island)","say":"Take peninsula, land almost surrounded by water. Break it: paene, meaning almost, plus insula, meaning island. A peninsula is almost an island.","show":{"t":"breakdown","word":"peninsula","hi":[3,4],"parts":[{"txt":"paene","gloss":"almost"},{"txt":"insula","gloss":"island"}]}},{"mood":"oops","cap":"isthmus: the -sthm- cluster","say":"Here's a spelling monster. Isthmus, a narrow neck of land, comes from isthmos, meaning neck. Watch that s-t-h-m pileup. Spell it i-s-t-h-m-u-s.","show":{"t":"word","word":"isthmus","hi":[1,4]}},{"mood":"happy","cap":"fjord: the Norse fj- cluster","say":"Norway gives us fjord, a narrow sea inlet between cliffs. That f-j start is pure Norse, a combination English almost never makes on its own. Spell it f-j-o-r-d.","show":{"t":"word","word":"fjord","hi":[0,2]}},{"mood":"happy","cap":"mesa = table, canyon = cañón (big pipe)","say":"Spanish explorers named much of the Americas. Mesa means table, for a flat-topped hill. And canyon comes from cañón, meaning a large pipe, for a deep gorge.","show":{"t":"list","items":[{"word":"mesa"},{"word":"canyon"}]}}]},"82":{"label":"Latin law words","scenes":[{"mood":"happy","cap":"Law ran on Latin for centuries","say":"English law was conducted in Latin for hundreds of years, so legal words still follow strict Latin spelling. Break them into roots and they behave.","show":{"t":"glyph","text":"LEX","sub":"law = Latin"}},{"mood":"oops","cap":"subpoena = sub + poena (penalty)","say":"A subpoena is a legal order to appear. Break it: sub, meaning under, plus poena, meaning penalty. Under penalty! Watch the silent first part. Spell it s-u-b-p-o-e-n-a.","show":{"t":"breakdown","word":"subpoena","hi":[3,5],"parts":[{"txt":"sub-","gloss":"under"},{"txt":"poena","gloss":"penalty"}]}},{"mood":"happy","cap":"jurisprudence = juris (of law) + prudentia","say":"Jurisprudence is the philosophy of law. Break it: juris, meaning of law, plus prudentia, meaning wisdom. The wisdom of law. And it ends e-n-c-e, not e-n-s-e.","show":{"t":"breakdown","word":"jurisprudence","hi":[0,5],"parts":[{"txt":"juris","gloss":"of law"},{"txt":"prudentia","gloss":"wisdom"}]}},{"mood":"excited","cap":"oligarchy = oligos (few) + arkhein (rule)","say":"Government types stack Greek roots too. Oligarchy is oligos, meaning few, plus arkhein, meaning to rule. Rule by a few. Swap the root and you get other governments.","show":{"t":"breakdown","word":"oligarchy","hi":[0,5],"parts":[{"txt":"oligos","gloss":"few"},{"txt":"arkhein","gloss":"to rule"}]}},{"mood":"happy","cap":"gerrymander = Governor Gerry + salamander","say":"And a fun one: gerrymander, redrawing districts unfairly, blends Governor Gerry with salamander, because a twisty district looked like one. Break long Latin words into roots and spell each piece.","show":{"t":"word","word":"gerrymander","hi":[0,5]}}]},"83":{"label":"Arabic al-","scenes":[{"mood":"happy","cap":"Arabic al- means \"the\"","say":"Arabic gave English a powerful clue: the prefix a-l, which simply means the. It got absorbed right into the word, so an al- beginning often means Arabic origin.","show":{"t":"glyph","text":"al-","sub":"the"}},{"mood":"excited","cap":"algebra = al-jabr (the reunion of parts)","say":"Math is full of it. Algebra comes from al-jabr, meaning the reunion of broken parts. And algorithm comes from al-Khwarizmi, the name of a great mathematician.","show":{"t":"breakdown","word":"algebra","hi":[0,2],"parts":[{"txt":"al-","gloss":"the"},{"txt":"jabr","gloss":"reunion of parts"}]}},{"mood":"happy","cap":"almanac = al-manakh (the calendar)","say":"More al- words: almanac, from al-manakh, meaning the calendar. And alcove, from al-qubba, meaning the vault. The al- keeps meaning the.","show":{"t":"list","items":[{"word":"almanac","hi":[0,2]},{"word":"alcove","hi":[0,2]}]}},{"mood":"happy","cap":"Astronomy: zenith, nadir, azimuth","say":"Arabic astronomers named the sky. Zenith, the point overhead, from samt. Nadir, the lowest point, from nazir, meaning opposite. Azimuth, a compass bearing, from al-samt.","show":{"t":"list","items":[{"word":"zenith"},{"word":"nadir"}]}},{"mood":"oops","cap":"Some hid the al-: chemistry, cotton","say":"Watch out, the al- sometimes vanished. Chemistry came from alchemy, and cotton came from qutn. So when a learned math or science word starts with al-, think Arabic, and think the.","show":{"t":"glyph","text":"al-","sub":"the · Arabic"}}]},"84":{"label":"Spanish loanwords","scenes":[{"mood":"happy","cap":"Spanish gave us landscape, animal & food words","say":"Spanish handed English a whole American landscape: canyons, sierras, and tornadoes, plus animal and food words. And it left behind some sneaky spelling clues.","show":{"t":"list","items":[{"word":"canyon"},{"word":"sierra"},{"word":"tornado"}]}},{"mood":"happy","cap":"-illo / -illa = a small version","say":"Watch for the ending spelled I L L O, or I L L A. It means a small version of something. An armadillo is a small armored one: armado, armored, plus illo.","show":{"t":"breakdown","word":"armadillo","hi":[6,4],"parts":[{"txt":"armado","gloss":"armored"},{"txt":"-illo","gloss":"small one"}]}},{"mood":"happy","cap":"guerrilla = guerra (war) + -illa (small)","say":"A guerrilla is a small war: guerra, war, plus illa. So a guerrilla fighter wages irregular, small-scale warfare against a bigger force.","show":{"t":"breakdown","word":"guerrilla","hi":[6,3],"parts":[{"txt":"guerra","gloss":"war"},{"txt":"-illa","gloss":"small"}]}},{"mood":"oops","cap":"guerrilla = double-R AND double-L","say":"Here is the trap. Guerrilla has a double R and a double L. Armadillo, vanilla, and sarsaparilla all keep that double L too. The double L is the big Spanish signal.","show":{"t":"word","word":"guerrilla","hi":[2,2]}},{"mood":"excited","cap":"Hear double-l → spell L-L","say":"So when a word names American land, animals, or food and has that doubled L sound, picture two L's side by side. That is your Spanish spelling signal.","show":{"t":"glyph","text":"-illo/-illa","sub":"double-l = small"}}]},"85":{"label":"Japanese loanwords","scenes":[{"mood":"happy","cap":"Japanese: consonant + vowel, over and over","say":"Japanese words are built from neat syllables: a consonant, then a vowel, again and again. Karate is ka, ra, te. No messy clusters, and they almost always end in a vowel.","show":{"t":"breakdown","word":"karate","hi":[0,6],"parts":[{"txt":"ka","gloss":""},{"txt":"ra","gloss":""},{"txt":"te","gloss":"hand"}]}},{"mood":"excited","cap":"Many are little compounds with meaning","say":"Better yet, many are tidy compounds. Karate is kara, empty, plus te, hand: empty hand. Judo is ju, gentle, plus do, way: the gentle way.","show":{"t":"breakdown","word":"karate","hi":[0,4],"parts":[{"txt":"kara","gloss":"empty"},{"txt":"te","gloss":"hand"}]}},{"mood":"happy","cap":"tsunami = tsu (harbor) + nami (wave)","say":"A tsunami is tsu, harbor, plus nami, wave: a harbor wave. That T S at the start is one single Japanese sound, even though it looks strange in English.","show":{"t":"breakdown","word":"tsunami","hi":[0,3],"parts":[{"txt":"tsu","gloss":"harbor"},{"txt":"nami","gloss":"wave"}]}},{"mood":"happy","cap":"origami = ori (fold) + kami (paper)","say":"Origami is ori, fold, plus kami, paper: folded paper. And karaoke is kara, empty, plus oke, orchestra: an empty orchestra waiting for you to sing.","show":{"t":"breakdown","word":"origami","hi":[0,3],"parts":[{"txt":"ori","gloss":"fold"},{"txt":"gami","gloss":"paper"}]}},{"mood":"excited","cap":"What you hear is what you spell","say":"So if a word ties to Japanese culture and has clean alternating sounds with no clusters, just spell it syllable by syllable. What you hear is what you spell.","show":{"t":"list","items":[{"word":"sushi"},{"word":"samurai"},{"word":"haiku"}]}}]},"86":{"label":"German loanwords","scenes":[{"mood":"happy","cap":"German words keep their German spelling","say":"German lent English big ideas about mood and mind, and the words kept their German spelling exactly. That makes them some of the oddest-looking words around.","show":{"t":"list","items":[{"word":"angst"},{"word":"kitsch"},{"word":"gestalt"}]}},{"mood":"oops","cap":"sch = the /sh/ sound (never sh)","say":"First trap: the sound you say as sh is spelled S C H in German words, never just S H. Schadenfreude starts with that sch, spelled S C H.","show":{"t":"glyph","text":"sch","sub":"= /sh/ sound"}},{"mood":"happy","cap":"schadenfreude = Schaden (harm) + Freude (joy)","say":"German loves to glue words together. Schadenfreude is Schaden, harm, plus Freude, joy: joy at someone else's misfortune.","show":{"t":"breakdown","word":"schadenfreude","hi":[0,6],"parts":[{"txt":"Schaden","gloss":"harm"},{"txt":"Freude","gloss":"joy"}]}},{"mood":"happy","cap":"wanderlust = wandern (wander) + Lust (desire)","say":"Wanderlust is wandern, to wander, plus Lust, desire: a desire to travel. And zeitgeist is Zeit, time, plus Geist, spirit: the spirit of an age.","show":{"t":"breakdown","word":"wanderlust","hi":[0,6],"parts":[{"txt":"wander","gloss":"to wander"},{"txt":"lust","gloss":"desire"}]}},{"mood":"excited","cap":"Spot ei, eu, or a glued compound → German","say":"So look for sch, or the letter pairs E I and E U, or two words glued together. Zeitgeist hides E I twice. Those clues shout German.","show":{"t":"glyph","text":"ei · eu · sch","sub":"German signals"}}]},"87":{"label":"Sanskrit & Hindi","scenes":[{"mood":"happy","cap":"Sanskrit = spiritual words; Hindi = household words","say":"Sanskrit gave English spiritual words like yoga and karma, while Hindi gave everyday ones like shampoo and bungalow. Both tend to be vowel-rich and clean to spell.","show":{"t":"list","items":[{"word":"karma"},{"word":"yoga"},{"word":"shampoo"}]}},{"mood":"happy","cap":"yoga = yuj (to unite); karma = action","say":"Yoga comes from yuj, to unite: the union of body and mind. Karma comes from karman, action: what you do comes back to you.","show":{"t":"breakdown","word":"yoga","hi":[0,4],"parts":[{"txt":"yoga","gloss":"union, from yuj"}]}},{"mood":"happy","cap":"mantra = man (think) + tra (tool)","say":"A mantra is man, to think, plus tra, a tool: a thinking tool, a sacred phrase you repeat. And an avatar is ava, down, plus tara, crossing: a god crossing down to earth.","show":{"t":"breakdown","word":"mantra","hi":[0,6],"parts":[{"txt":"man","gloss":"think"},{"txt":"tra","gloss":"tool"}]}},{"mood":"love","cap":"juggernaut = Jagat (world) + natha (lord)","say":"My favorite: juggernaut. It is Jagat, world, plus natha, lord: Lord of the Universe. It was a temple cart so huge it crushed all in its path. Note the double G, spelled J U G.","show":{"t":"breakdown","word":"juggernaut","hi":[0,3],"parts":[{"txt":"Jagat","gloss":"world"},{"txt":"natha","gloss":"lord"}]}},{"mood":"excited","cap":"Final -a is /uh/ — never add -h","say":"Many of these end in the letter A, said like uh: karma, mantra, chakra. Spell them clean and never add an H at the end. It is karma, not karmah.","show":{"t":"glyph","text":"-a","sub":"/uh/, no -h"}}]},"88":{"label":"Old Norse loanwords","scenes":[{"mood":"happy","cap":"Vikings gave us short, sturdy words","say":"The Vikings spoke Old Norse, and they gave English short, sturdy words about law, the sea, and daily life. Many start with a strong S K sound.","show":{"t":"list","items":[{"word":"skill"},{"word":"sky"},{"word":"skull"}]}},{"mood":"excited","cap":"sk- is a reliable Norse signal","say":"That cluster spelled S K is a reliable Norse fingerprint. Skill came from skil, meaning distinction. Sky, skin, skull, and skate all carry the same Viking S K.","show":{"t":"glyph","text":"sk-","sub":"Norse signal"}},{"mood":"love","cap":"berserk = ber (bear) + serkr (shirt)","say":"Here is a wild one: berserk. It is ber, bear, plus serkr, shirt: a warrior in a bear shirt, fighting in a frenzy. Now it just means wildly out of control.","show":{"t":"breakdown","word":"berserk","hi":[0,3],"parts":[{"txt":"ber","gloss":"bear"},{"txt":"serk","gloss":"shirt"}]}},{"mood":"happy","cap":"ransack = rann (house) + saka (seek)","say":"To ransack is rann, house, plus saka, seek: to search a house violently. And starboard is the steering side of a ship, from stjorn, steering, plus bord, side.","show":{"t":"breakdown","word":"ransack","hi":[3,4],"parts":[{"txt":"rann","gloss":"house"},{"txt":"sack","gloss":"seek"}]}},{"mood":"happy","cap":"Even fjord & sleet are Norse","say":"The Vikings named the sea too. Fjord, spelled F J O R D, and sleet both came from Norse. See S K, or a short blunt sea word, and think Viking.","show":{"t":"word","word":"fjord","hi":[0,2]}}]},"89":{"label":"Rhetoric of lying","scenes":[{"mood":"happy","cap":"Words for the tricks of persuasion","say":"These fancy words name the tricks of persuasion and deception. They come from Greek and Latin roots, and they show up in championship rounds.","show":{"t":"list","items":[{"word":"prevarication"},{"word":"equivocation"},{"word":"obfuscation"}]}},{"mood":"happy","cap":"equivocation = equi (equal) + vox (voice)","say":"Equivocation is equi, equal, plus vox, voice: giving two meanings equal voice on purpose, so your words stay slippery and ambiguous.","show":{"t":"breakdown","word":"equivocation","hi":[0,8],"parts":[{"txt":"equi","gloss":"equal"},{"txt":"voc","gloss":"voice"}]}},{"mood":"happy","cap":"obfuscation = ob- + fuscare (to darken)","say":"Obfuscation is ob, plus the Latin fuscare, to darken: deliberately darkening your meaning so no one can understand it.","show":{"t":"breakdown","word":"obfuscation","hi":[0,6],"parts":[{"txt":"ob-","gloss":"over"},{"txt":"fusc","gloss":"darken"}]}},{"mood":"love","cap":"apophasis = apo (away) + phasis (speech)","say":"My favorite: apophasis, apo, away, plus phasis, speech. It means mentioning a thing by saying you won't mention it. I won't bring up his record, see?","show":{"t":"breakdown","word":"apophasis","hi":[0,4],"parts":[{"txt":"apo","gloss":"away"},{"txt":"phasis","gloss":"speech"}]}},{"mood":"oops","cap":"apophasis = A-P-O-P-H-A-S-I-S; chiasmus -ch- = /k/","say":"Watch the Greek spellings. Apophasis hides a P H for its f sound, spelled A P O P H. And chiasmus starts C H, even though it sounds like a k.","show":{"t":"word","word":"chiasmus","hi":[0,2]}}]},"90":{"label":"Homophones","scenes":[{"mood":"happy","cap":"Same sound, different spelling & meaning","say":"Homophones sound exactly alike but are spelled differently and mean different things. You can't crack them by ear; you need the meaning and the story behind them.","show":{"t":"list","items":[{"word":"principal"},{"word":"principle"}]}},{"mood":"oops","cap":"principal = your pal; principle = a rule","say":"Principal, ending A L, is the head of a school, your pal. Principle, ending L E, is a rule you learn. The pal trick keeps them straight.","show":{"t":"word","word":"principal","hi":[7,2]}},{"mood":"happy","cap":"stationary = standing; stationery = paper","say":"Stationary with an A means standing still. Stationery with an E means paper. The trick: the E in stationery matches the E in paper.","show":{"t":"word","word":"stationery","hi":[7,1]}},{"mood":"love","cap":"stationer = a fixed-station shopkeeper","say":"And the story makes it logical. A stationer was a shopkeeper with a fixed station, a shop, who sold paper. So stationery, the paper, ends with that shopkeeper's E R.","show":{"t":"breakdown","word":"stationery","hi":[7,3],"parts":[{"txt":"station","gloss":"fixed shop"},{"txt":"-ery","gloss":"from stationer"}]}},{"mood":"excited","cap":"affect = verb; effect = result","say":"One more pair. Affect with an A is the verb, to influence. Effect with an E is the noun, the result. Let the meaning pick your first letter, and you'll spell them right.","show":{"t":"list","items":[{"word":"affect","hi":[0,1]},{"word":"effect","hi":[0,1]}]}}]},"91":{"label":"Contronyms","scenes":[{"mood":"happy","cap":"One word, two opposite meanings","say":"Contronyms are words that mean two opposite things at once, and only the sentence tells you which. They are little spelling and meaning puzzles.","show":{"t":"list","items":[{"word":"sanction"},{"word":"cleave"},{"word":"screen"}]}},{"mood":"happy","cap":"sanction = approve OR penalize","say":"Take sanction. It can mean to officially approve something, or to penalize it with restrictions. Same spelling, opposite jobs, decided only by context.","show":{"t":"word","word":"sanction"}},{"mood":"love","cap":"cleave = split apart OR stick together","say":"Cleave is the wildest one. It can mean to split apart, or to stick closely together. That's because it grew from two different Old English words that merged into one spelling.","show":{"t":"breakdown","word":"cleave","hi":[0,6],"parts":[{"txt":"cleofan","gloss":"to split"},{"txt":"clifian","gloss":"to stick"}]}},{"mood":"happy","cap":"buckle, screen, weather, fast all flip","say":"There are many more. Buckle can fasten or collapse. Screen can show or hide. Weather can withstand or wear away. Fast can mean moving quickly, or stuck firmly in place.","show":{"t":"list","items":[{"word":"buckle"},{"word":"weather"},{"word":"fast"}]}},{"mood":"oops","cap":"in- here means INTO flames, not NOT","say":"Now the real trap. Inflammable means it can catch fire. Here that in, spelled I N, means into flames, not not. So inflammable is dangerous, not safe.","show":{"t":"breakdown","word":"inflammable","hi":[0,2],"parts":[{"txt":"in-","gloss":"into"},{"txt":"flam","gloss":"flame"}]}}]},"92":{"label":"Eponyms","scenes":[{"mood":"happy","cap":"Words made from people's names","say":"Eponyms are words built from people's names, real or legendary. From boycott to sandwich, each one carries a little story that makes its spelling stick.","show":{"t":"list","items":[{"word":"boycott"},{"word":"sandwich"},{"word":"cardigan"}]}},{"mood":"love","cap":"boycott = Captain Charles Boycott","say":"To boycott means to refuse to deal with someone. It comes from Captain Charles Boycott, an Irish land agent everyone refused to work with. His name became the word.","show":{"t":"word","word":"boycott","hi":[5,2]}},{"mood":"happy","cap":"sandwich = the Earl of Sandwich","say":"A sandwich is named for the Earl of Sandwich, who put his food between bread so he could keep gambling without stopping to eat. Handy, and delicious.","show":{"t":"word","word":"sandwich"}},{"mood":"happy","cap":"malapropism = Mrs. Malaprop in a 1775 play","say":"A malapropism, using the wrong word for a similar one, comes from Mrs. Malaprop, a character in a play from 1775 who muddled her words constantly.","show":{"t":"word","word":"malapropism"}},{"mood":"oops","cap":"Keep the name's spelling: boycott = two t's","say":"Here's the spelling secret. Eponyms keep the person's own spelling. Boycott has two T's because the name Boycott did. Quixotic keeps its X from Don Quixote, spelled Q U I X.","show":{"t":"word","word":"quixotic","hi":[3,1]}}]},"93":{"label":"Mythology words","scenes":[{"mood":"happy","cap":"Gods & heroes became everyday words","say":"Myth gave English hundreds of words, straight from the names of gods and heroes. Because they come from proper names, their spellings can look unusual.","show":{"t":"list","items":[{"word":"volcano"},{"word":"panic"},{"word":"siren"}]}},{"mood":"love","cap":"volcano ← Vulcan; panic ← Pan","say":"Volcano comes from Vulcan, the Roman god of fire. Panic comes from Pan, the goat-god whose sudden appearance filled people with terror. The gods are hiding in plain sight.","show":{"t":"breakdown","word":"volcano","hi":[0,6],"parts":[{"txt":"Vulcan","gloss":"god of fire"}]}},{"mood":"happy","cap":"herculean ← Hercules; tantalize ← Tantalus","say":"Heroes became adjectives too. Herculean, needing huge strength, comes from Hercules. And to tantalize, to dangle something just out of reach, comes from Tantalus.","show":{"t":"breakdown","word":"tantalize","hi":[0,7],"parts":[{"txt":"Tantalus","gloss":"reaching forever"}]}},{"mood":"happy","cap":"labyrinth & marathon came from places","say":"Even places gave us words. Labyrinth comes from the Labyrinth that caged the Minotaur, and marathon comes from the town of Marathon, where the famous run began.","show":{"t":"word","word":"labyrinth","hi":[3,1]}},{"mood":"oops","cap":"Greek -th- and y-as-a-vowel are the clues","say":"Watch two Greek clues. The th sound is spelled T H, as in promethean. And the letter Y works as a vowel inside the word, as in labyrinth, spelled L A B Y.","show":{"t":"glyph","text":"-th- · y","sub":"Greek signals"}}]},"94":{"label":"Words about time","scenes":[{"mood":"happy","cap":"Time words go way beyond chron-","say":"Time vocabulary stretches far past chron. Latin tempus, Greek aion, and hora all build time words, each with its own flavor and its own spelling clues.","show":{"t":"list","items":[{"word":"temporal"},{"word":"aeon"},{"word":"ephemeral"}]}},{"mood":"love","cap":"ephemeral = epi (upon) + hemera (day)","say":"My favorite is ephemeral. It is epi, upon, plus hemera, a day: lasting only a day, here and gone. Picture a mayfly living for one bright afternoon.","show":{"t":"breakdown","word":"ephemeral","hi":[0,7],"parts":[{"txt":"epi-","gloss":"upon"},{"txt":"hemera","gloss":"day"}]}},{"mood":"happy","cap":"tempus (time): contemporary, extemporaneous","say":"Latin tempus, time, builds a family. Contemporary is con, plus tempus: living at the same time. Extemporaneous is ex tempore, out of the moment: spoken with no preparation.","show":{"t":"breakdown","word":"contemporary","hi":[0,9],"parts":[{"txt":"con-","gloss":"together"},{"txt":"tempor","gloss":"time"}]}},{"mood":"happy","cap":"aevum (age): medieval, primeval","say":"The root aevum means age. Medieval is medi, middle, plus aevum: of the Middle Ages. Primeval is prim, first, plus aevum: of the earliest age of all.","show":{"t":"breakdown","word":"medieval","hi":[0,4],"parts":[{"txt":"medi-","gloss":"middle"},{"txt":"eval","gloss":"age, from aevum"}]}},{"mood":"oops","cap":"ephemeral: P-H, and -er- not -or-","say":"Two traps. Ephemeral takes a Greek P H for its f sound, and ends E R A L, not O R A L. And medieval is spelled M E D I E, that I before E coming from aevum.","show":{"t":"word","word":"ephemeral","hi":[1,2]}}]},"95":{"label":"Size & quantity words","scenes":[{"mood":"happy","cap":"Roots for big, small, many & few","say":"Beyond number prefixes, Latin and Greek give us roots for big and small, many and few. They combine into precise words for measuring the world.","show":{"t":"list","items":[{"word":"colossal"},{"word":"minuscule"},{"word":"myriad"}]}},{"mood":"happy","cap":"tiny: diminutive, infinitesimal","say":"For tiny things: diminutive comes from diminuere, to lessen. And infinitesimal is infinitus, without end, plus esimal, a fraction: so small it is almost zero.","show":{"t":"breakdown","word":"infinitesimal","hi":[0,8],"parts":[{"txt":"infinit","gloss":"without end"},{"txt":"-esimal","gloss":"a fraction"}]}},{"mood":"love","cap":"colossal ← Colossus; gargantuan ← Gargantua","say":"For huge things, the words borrow giants. Colossal comes from the Colossus of Rhodes, a giant statue. Gargantuan comes from Gargantua, a storybook giant.","show":{"t":"word","word":"gargantuan"}},{"mood":"happy","cap":"myriad = myrioi (ten thousand)","say":"For great numbers: myriad comes from the Greek myrioi, ten thousand, and now means a huge, countless amount. Paucity, from paucus, few, is the opposite: a small number.","show":{"t":"breakdown","word":"myriad","hi":[0,6],"parts":[{"txt":"myrioi","gloss":"ten thousand"}]}},{"mood":"oops","cap":"minuscule = -us- not -is-; myriad's y","say":"Big trap: minuscule is spelled M I N U S, with a U, not an I. People mix it up with mini. And myriad uses Y as a vowel, spelled M Y R, a Greek clue.","show":{"t":"word","word":"minuscule","hi":[3,2]}}]},"96":{"label":"Personality words","scenes":[{"mood":"happy","cap":"Top-tier words for talkers & thinkers","say":"These are championship-level words for describing people: their courage, their pride, their honesty. Crack the roots, and the spellings stop being scary.","show":{"t":"list","items":[{"word":"pusillanimous"},{"word":"supercilious"},{"word":"probity"}]}},{"mood":"love","cap":"pusillanimous = pusillus (tiny) + animus (spirit)","say":"Here's a gem for a coward: pusillanimous. It is pusillus, tiny, plus animus, spirit: tiny-spirited. A person too timid to be brave.","show":{"t":"breakdown","word":"pusillanimous","hi":[0,7],"parts":[{"txt":"pusillus","gloss":"tiny"},{"txt":"animus","gloss":"spirit"}]}},{"mood":"happy","cap":"supercilious = super- + cilium (eyebrow)","say":"For an arrogant person: supercilious. It is super, above, plus cilium, eyebrow: literally raising your eyebrow above everyone else, looking down on them.","show":{"t":"breakdown","word":"supercilious","hi":[0,5],"parts":[{"txt":"super-","gloss":"above"},{"txt":"cilium","gloss":"eyebrow"}]}},{"mood":"happy","cap":"probity = probus (honest); rectitude = rectus (straight)","say":"For good character: probity comes from probus, honest, and means complete honesty. Rectitude comes from rectus, straight, and means moral straightness.","show":{"t":"breakdown","word":"rectitude","hi":[0,4],"parts":[{"txt":"rectus","gloss":"straight"},{"txt":"-itude","gloss":"state of"}]}},{"mood":"oops","cap":"pusillanimous keeps the double-l of pusillus","say":"Watch the spelling. Pusillanimous keeps a double L, spelled P U S I L L, straight from pusillus. Hear the root, and you'll know where the L's belong.","show":{"t":"word","word":"pusillanimous","hi":[3,2]}}]},"97":{"label":"The schwa problem","scenes":[{"mood":"happy","cap":"The schwa: the lazy /uh/ sound","say":"The schwa is the soft, unstressed uh sound, the most common vowel in English. The trouble is, it can be spelled with any vowel: a, e, i, o, or u.","show":{"t":"glyph","text":"schwa","sub":"/uh/, any vowel"}},{"mood":"oops","cap":"separate has -ar-, not -er-","say":"That's why separate trips everyone up. The middle is a schwa, so people write S E P E R, with an E. But it's actually A R, spelled S E P A R.","show":{"t":"word","word":"separate","hi":[3,2]}},{"mood":"excited","cap":"Strategy: stress a related word","say":"Here's the best trick. Find a relative where that lazy syllable gets stressed. Competition hides a schwa, but say compete, and the stressed E pops out clearly.","show":{"t":"breakdown","word":"competition","hi":[3,1],"parts":[{"txt":"compete","gloss":"stress reveals the e"}]}},{"mood":"happy","cap":"definition → define reveals the i","say":"It works again and again. Unsure about definition? Say define, and the stressed I shows up. Unsure about explanation? Say explain, and the A appears.","show":{"t":"breakdown","word":"definition","hi":[3,1],"parts":[{"txt":"define","gloss":"stress reveals the i"}]}},{"mood":"excited","cap":"Stress the root → see the vowel","say":"So when a schwa hides a vowel, don't guess. Stretch out a related word until that syllable gets the stress, and it will tell you exactly which vowel to spell.","show":{"t":"list","items":[{"word":"library"},{"word":"february"},{"word":"privilege"}]}}]},"98":{"label":"Knowledge words","scenes":[{"mood":"happy","cap":"Words for learning come from teach + know roots.","say":"Today's words are all about learning and knowing. They come from Greek mathein, to learn, Latin docere, to teach, and scire, to know.","show":{"t":"glyph","text":"scire","sub":"to know"}},{"mood":"happy","cap":"didaskein (to teach) → didactic","say":"Take didactic, spelled D, I, D, A, C, T, I, C. It comes from the Greek didaskein, to teach, so something didactic is meant to teach or instruct you.","show":{"t":"breakdown","word":"didactic","hi":[0,5],"parts":[{"txt":"didaskein","gloss":"to teach"}]}},{"mood":"happy","cap":"ne- (not) + scire (know) → nescient","say":"Now flip to not knowing. Nescient takes ne, meaning not, plus scire, to know. So a nescient person is simply lacking knowledge.","show":{"t":"breakdown","word":"nescient","hi":[0,2],"parts":[{"txt":"ne-","gloss":"not"},{"txt":"scire","gloss":"to know"}]}},{"mood":"oops","cap":"erudite ends -ITE, not -ight!","say":"Watch the trap in erudite, spelled E, R, U, D, I, T, E. It started from e plus rudis, meaning rough, so an erudite person is polished by learning. End it I, T, E, never i, g, h, t.","show":{"t":"word","word":"erudite","hi":[5,2]}},{"mood":"excited","cap":"Spot the root, unlock the word.","say":"So whenever you spot scire, think know, and ne for not. Find the teaching and knowing roots, and these big words open right up.","show":{"t":"glyph","text":"scire","sub":"to know"}}]},"99":{"label":"44 sounds, many spellings","scenes":[{"mood":"happy","cap":"26 letters, but 44 sounds.","say":"Here's the puzzle of English. We have only twenty six letters, but forty four different sounds. So one sound can be spelled lots of ways.","show":{"t":"glyph","text":"26 ≠ 44","sub":"letters vs sounds"}},{"mood":"happy","cap":"The /f/ sound has 4 spellings.","say":"Listen to the f sound. It can be plain f in fun, p h in phone for Greek words, double f in cliff after a short vowel, and g h in enough.","show":{"t":"list","items":[{"word":"phone","hi":[0,2]},{"word":"cliff","hi":[3,2]},{"word":"enough","hi":[4,2]}]}},{"mood":"happy","cap":"Origin + position pick the spelling.","say":"The trick is origin plus position. Take technique, spelled with q, u, e on the end, because that q, u, e ending comes from French, as in unique.","show":{"t":"word","word":"technique","hi":[6,3]}},{"mood":"oops","cap":"-ti-, -ci-, -ssi- all say /sh/.","say":"Watch out for the sh sound. It hides as t, i in nation, c, i in musician, and s, s, i in mission. Same hiss, three different spellings.","show":{"t":"list","items":[{"word":"nation","hi":[2,2]},{"word":"musician","hi":[5,2]}]}},{"mood":"excited","cap":"onoma + poiein → onomatopoeia","say":"And my favorite, onomatopoeia, from onoma, a name, plus poiein, to make. It means making a name from a sound, like buzz or hiss.","show":{"t":"breakdown","word":"onomatopoeia","hi":[0,5],"parts":[{"txt":"onoma","gloss":"name"},{"txt":"poiein","gloss":"to make"}]}}]},"100":{"label":"Championship words","scenes":[{"mood":"excited","cap":"The hardest words decide championships.","say":"These are the championship words, the ones that decide who wins. The secret is always the same. Ask for the origin first, then use that language's rules.","show":{"t":"glyph","text":"origin 1st","sub":"then the rules"}},{"mood":"happy","cap":"triskaideka (13) + phobia → fear of 13","say":"Greek words decode perfectly. Triskaidekaphobia looks scary, but triskaideka means thirteen, and phobia means fear. So it's simply the fear of the number thirteen.","show":{"t":"breakdown","word":"triskaidekaphobia","hi":[0,11],"parts":[{"txt":"triskaideka","gloss":"thirteen"},{"txt":"phobia","gloss":"fear"}]}},{"mood":"oops","cap":"connoisseur: double-n, double-s, French -eur","say":"French words break our intuition. Connoisseur, spelled with a double n and a double s, ends in e, u, r, not e, r. Three French surprises in one word.","show":{"t":"word","word":"connoisseur","hi":[9,3]}},{"mood":"happy","cap":"German: sch=/sh/, au=/ow/, eu=/oy/","say":"German compounds follow strict rules too. In schadenfreude, s, c, h says sh, a, u says ow, and e, u says oy. Know those three, and you can spell it.","show":{"t":"word","word":"schadenfreude","hi":[0,3]}},{"mood":"excited","cap":"Say it. Spell it. Say it again.","say":"So the winner isn't who memorized the most. It's whose pattern sense fires fastest. Ask the origin, apply the rules, and say it, spell it, say it again.","show":{"t":"glyph","text":"patterns","sub":"fire fast"}}]},"101":{"label":"Giving & hoarding","scenes":[{"mood":"happy","cap":"Words for generous vs miserly.","say":"This group runs from big givers to tight hoarders. Most are built on Latin roots about giving and holding back. Let's open a few up.","show":{"t":"glyph","text":"give ↔ keep","sub":"two sides"}},{"mood":"love","cap":"magna (great) + animus (soul) → magnanimous","say":"Start with magnanimous. It joins magna, meaning great, and animus, meaning soul. A magnanimous person has a great soul, generous even in forgiving an insult.","show":{"t":"breakdown","word":"magnanimous","hi":[0,4],"parts":[{"txt":"magna","gloss":"great"},{"txt":"animus","gloss":"soul"}]}},{"mood":"happy","cap":"munus (gift) + facere (make) → munificent","say":"Then munificent, spelled M, U, N, I, F, I, C, E, N, T. It's munus, a gift, plus facere, to make. Someone munificent makes gifts, and is extremely generous.","show":{"t":"breakdown","word":"munificent","hi":[0,3],"parts":[{"txt":"munus","gloss":"gift"},{"txt":"facere","gloss":"make"}]}},{"mood":"oops","cap":"avaricious, rapacious — all end -ious!","say":"Now the hoarders. Avaricious comes from avarus, greedy, and rapacious from rapax, seizing. The spelling trap is the ending. Both finish c, i, o, u, s.","show":{"t":"list","items":[{"word":"avaricious","hi":[6,4]},{"word":"rapacious","hi":[5,4]}]}},{"mood":"excited","cap":"Root tells the meaning; -ious ends it.","say":"So let the root tell you the meaning, gift or greed, and remember that whole hoarding family ends in i, o, u, s. Two clues, one right spelling.","show":{"t":"glyph","text":"-ious","sub":"shared ending"}}]},"102":{"label":"Latin cedere (go)","scenes":[{"mood":"happy","cap":"Movement words = prefix + motion root.","say":"Movement words are a prefix plus a root that means move. A big one is the Latin cedere, spelled C, E, D, E, R, E, meaning to go.","show":{"t":"glyph","text":"cedere","sub":"to go"}},{"mood":"happy","cap":"pre- (before) + cedere → precede","say":"Add prefixes and watch it grow. Pre means before, so precede is to go before. Re means back, so recede is to go back.","show":{"t":"breakdown","word":"precede","hi":[0,3],"parts":[{"txt":"pre-","gloss":"before"},{"txt":"cedere","gloss":"to go"}]}},{"mood":"happy","cap":"se- (apart) + cedere → secede","say":"Or secede. Se means apart, so to secede is to go apart, to formally withdraw from an alliance. Same root, brand new direction.","show":{"t":"breakdown","word":"secede","hi":[0,2],"parts":[{"txt":"se-","gloss":"apart"},{"txt":"cedere","gloss":"to go"}]}},{"mood":"oops","cap":"supersede ends -SEDE, not -cede!","say":"Here's the famous trap. Supersede looks like the others, but it ends s, e, d, e, not c, e, d, e. It comes from sedere, to sit, meaning to sit above and replace.","show":{"t":"word","word":"supersede","hi":[5,4]}},{"mood":"excited","cap":"Know prefix + root = know the word.","say":"So count the prefix, find cedere for go, and you'll spell precede, recede, and secede. Just remember supersede is the one that sits apart with s, e, d, e.","show":{"t":"glyph","text":"cedere","sub":"to go"}}]},"103":{"label":"Literary devices","scenes":[{"mood":"happy","cap":"Greek & Latin names for writers' tools.","say":"These are the tools of poets and writers, and most names come straight from Greek. Crack the root, and a fancy term turns friendly.","show":{"t":"glyph","text":"litera","sub":"letter"}},{"mood":"happy","cap":"al- + litera (letter) → alliteration","say":"Take alliteration, built from al plus litera, meaning letter. It's repeating the same beginning consonant sound, like the same consonant starting each stressed beat.","show":{"t":"breakdown","word":"alliteration","hi":[0,6],"parts":[{"txt":"al-","gloss":"to"},{"txt":"litera","gloss":"letter"}]}},{"mood":"happy","cap":"meta- (across) + pherein (carry) → metaphor","say":"Then metaphor, from meta, plus pherein, to carry. A metaphor carries one idea across to another, a comparison made without using like or as.","show":{"t":"breakdown","word":"metaphor","hi":[0,4],"parts":[{"txt":"meta-","gloss":"across"},{"txt":"pherein","gloss":"carry"}]}},{"mood":"oops","cap":"syzygy = S-Y-Z-Y-G-Y (three y's!)","say":"Now a spelling shocker. Syzygy means two poetic feet yoked together, and it's spelled S, Y, Z, Y, G, Y. Six letters, and three of them are y, doing the vowels.","show":{"t":"word","word":"syzygy","hi":[1,1]}},{"mood":"excited","cap":"Greek roots spell Greek terms.","say":"So these terms follow Greek spelling. Metonymy even hides nym, from onoma, name. Find the Greek root, and the strange spelling starts to make sense.","show":{"t":"breakdown","word":"metonymy","hi":[4,3],"parts":[{"txt":"nym","gloss":"name"}]}}]},"104":{"label":"Light & color words","scenes":[{"mood":"happy","cap":"From Latin lux (light) & Greek khroma (color).","say":"Color and light words come from Latin lux, meaning light, and Greek khroma, meaning color. They shimmer through science, art, and poetry.","show":{"t":"glyph","text":"lux","sub":"light"}},{"mood":"happy","cap":"in- + candere (glow white) → incandescent","say":"Take incandescent, from in plus candere, to glow white. Something incandescent glows from high heat, strikingly bright and radiant.","show":{"t":"breakdown","word":"incandescent","hi":[0,2],"parts":[{"txt":"in-","gloss":"in"},{"txt":"candere","gloss":"glow white"}]}},{"mood":"love","cap":"dia- (through) + phainein (show) → diaphanous","say":"And diaphanous, from dia, through, plus phainein, to show. It means so thin that light shows through, sheer and gossamer light.","show":{"t":"breakdown","word":"diaphanous","hi":[0,3],"parts":[{"txt":"dia-","gloss":"through"},{"txt":"phainein","gloss":"show"}]}},{"mood":"oops","cap":"phosphorescent has TWO -ph- signals!","say":"Spelling trap time. Phosphorescent has two p h spellings, both Greek signals. Spell it P, H, O, S, P, H, and watch for the s, c before e that says s.","show":{"t":"word","word":"phosphorescent","hi":[4,2]}},{"mood":"excited","cap":"Roots glow with meaning.","say":"So let the roots light the way. Candere glows, phainein shows, and lux means light. See the root, and these dazzling words spell themselves.","show":{"t":"glyph","text":"lux","sub":"light"}}]},"105":{"label":"Sound & music words","scenes":[{"mood":"happy","cap":"Greek roots for sweet & harsh sounds.","say":"These words describe sounds, sweet ones and harsh ones, built from Greek and Latin roots. Hear the root, and you hear the meaning.","show":{"t":"glyph","text":"mel","sub":"honey"}},{"mood":"love","cap":"mel (honey) + fluere (flow) → mellifluous","say":"Start sweet with mellifluous, from mel, meaning honey, plus fluere, to flow. A mellifluous voice flows like honey, smooth and lovely.","show":{"t":"breakdown","word":"mellifluous","hi":[0,3],"parts":[{"txt":"mel","gloss":"honey"},{"txt":"fluere","gloss":"flow"}]}},{"mood":"happy","cap":"stridere (to creak) → strident","say":"Now harsh. Strident comes from stridere, to creak, so a strident sound is loud and grating. And raucous, from raucus, hoarse, means harsh and loud.","show":{"t":"breakdown","word":"strident","hi":[0,6],"parts":[{"txt":"stridere","gloss":"to creak"}]}},{"mood":"oops","cap":"mellifluous = double-L; polysemy = Y vowel","say":"Two spelling traps. Mellifluous needs a double l, spelled M, E, L, L. And polysemy uses y as a Greek vowel, spelled P, O, L, Y, S, E, M, Y.","show":{"t":"word","word":"polysemy","hi":[3,1]}},{"mood":"excited","cap":"Honey flows, creaks grate.","say":"So honey flows in mellifluous, and creaks grate in strident. Hear the root inside the word, and the meaning, and the spelling, come along for free.","show":{"t":"glyph","text":"mel · fluere","sub":"honey flows"}}]},"106":{"label":"Architecture words","scenes":[{"mood":"happy","cap":"Building words from Latin, Greek & French.","say":"Architecture words come from many languages and name the parts of buildings. Many carry a tidy root that tells you exactly what they are.","show":{"t":"glyph","text":"fenestra","sub":"window"}},{"mood":"happy","cap":"fenestra (window) → fenestration","say":"Take fenestration, from the Latin fenestra, meaning window. Fenestration is just the arrangement of windows in a building. One root, whole meaning.","show":{"t":"breakdown","word":"fenestration","hi":[0,8],"parts":[{"txt":"fenestra","gloss":"window"}]}},{"mood":"love","cap":"navis (ship) → nave","say":"Here's a lovely one. Nave, the central body of a church, comes from navis, meaning ship. Look up at a tall nave, and it can feel like an upside down ship.","show":{"t":"breakdown","word":"nave","hi":[0,4],"parts":[{"txt":"navis","gloss":"ship"}]}},{"mood":"oops","cap":"crenellation has a double-L!","say":"Watch this trap. Crenellation, from crena, meaning notch, is the notched top of a castle wall. Spell it with a double l, C, R, E, N, E, L, L.","show":{"t":"word","word":"crenellation","hi":[5,2]}},{"mood":"excited","cap":"The root names the part.","say":"So the root names the part. Fenestra is window, navis is ship, crena is notch. Find the root, and even a grand building word spells out neatly.","show":{"t":"glyph","text":"fenestra","sub":"window"}}]},"107":{"label":"Flora & fauna words","scenes":[{"mood":"happy","cap":"Nature names from Latin & Greek.","say":"Science names for plants and animals come from Latin and Greek. Each one packs a root that describes how a living thing behaves or grows.","show":{"t":"glyph","text":"arbor","sub":"tree"}},{"mood":"happy","cap":"de- + cadere (fall) → deciduous","say":"Take deciduous, from de plus cadere, meaning to fall. A deciduous tree drops, or falls, its leaves each year. Spell it ending d, u, o, u, s.","show":{"t":"breakdown","word":"deciduous","hi":[0,2],"parts":[{"txt":"de-","gloss":"down"},{"txt":"cadere","gloss":"to fall"}]}},{"mood":"happy","cap":"conus (cone) + ferre (bear) → coniferous","say":"Its opposite is coniferous, from conus, a cone, plus ferre, to bear. A coniferous tree bears cones, and stays green all winter.","show":{"t":"breakdown","word":"coniferous","hi":[0,5],"parts":[{"txt":"conus","gloss":"cone"},{"txt":"ferre","gloss":"bear"}]}},{"mood":"oops","cap":"phylogeny = ph (Greek) + Y twice!","say":"Spelling alert. Phylogeny, the history of how creatures evolved, is full Greek. It starts p h, and uses y as a vowel twice, spelled P, H, Y, then later G, E, N, Y.","show":{"t":"word","word":"phylogeny","hi":[0,2]}},{"mood":"excited","cap":"Leaves fall, cones bear.","say":"So leaves fall in deciduous, cones are borne in coniferous, and arbor means tree. Spot the root, and a science word turns into a picture.","show":{"t":"glyph","text":"cadere","sub":"to fall"}}]},"108":{"label":"Greek -logy roots","scenes":[{"mood":"happy","cap":"Deep words from theos, logos, psyche.","say":"Philosophy and religion words are almost all Greek, from theos, god, logos, reason, and psyche, soul. These are the deepest roots we have.","show":{"t":"glyph","text":"logos","sub":"reason · study"}},{"mood":"happy","cap":"eskhatos (last) → eschatology","say":"Take eschatology, from eskhatos, meaning last, plus logy, the study of. It's the study of the last things, the end times.","show":{"t":"breakdown","word":"eschatology","hi":[0,5],"parts":[{"txt":"eskhatos","gloss":"last"},{"txt":"-logy","gloss":"study of"}]}},{"mood":"happy","cap":"episteme (knowledge) → epistemology","say":"Then epistemology, from episteme, meaning knowledge. So epistemology is the study of how we know things, the theory of knowledge itself.","show":{"t":"breakdown","word":"epistemology","hi":[0,8],"parts":[{"txt":"episteme","gloss":"knowledge"},{"txt":"-logy","gloss":"study of"}]}},{"mood":"oops","cap":"blasphemy = -PH- Greek signal!","say":"Spelling trap. Blasphemy, meaning disrespect toward God, comes from blasphemia, evil speech. That f sound is really p h, so spell it B, L, A, S, P, H.","show":{"t":"word","word":"blasphemy","hi":[4,2]}},{"mood":"excited","cap":"-logy = study of.","say":"So whenever you see l, o, g, y, think the study of, and look for the Greek root in front. Eskhatos, episteme, and the whole deep family opens up.","show":{"t":"glyph","text":"-logy","sub":"study of"}}]},"109":{"label":"Rare loanwords","scenes":[{"mood":"happy","cap":"Words from Hebrew, Malay, Welsh & more.","say":"Some championship words come from Hebrew, Malay, Welsh, and Afrikaans. Latin and Greek won't help here, so we learn each language's own patterns.","show":{"t":"glyph","text":"origin?","sub":"ask first"}},{"mood":"love","cap":"orang (person) + hutan (forest) → orangutan","say":"From Malay comes orangutan, built from orang, meaning person, plus hutan, meaning forest. A person of the forest. Spell it O, R, A, N, G, U, T, A, N.","show":{"t":"breakdown","word":"orangutan","hi":[0,5],"parts":[{"txt":"orang","gloss":"person"},{"txt":"hutan","gloss":"forest"}]}},{"mood":"happy","cap":"cor (dwarf) + gi (dog) → corgi","say":"From Welsh comes corgi, from cor, meaning dwarf, plus gi, meaning dog. A corgi is literally a dwarf dog, short legs and all.","show":{"t":"breakdown","word":"corgi","hi":[0,3],"parts":[{"txt":"cor","gloss":"dwarf"},{"txt":"gi","gloss":"dog"}]}},{"mood":"oops","cap":"aardvark starts with double-A!","say":"Here's a spelling surprise. Aardvark, from Afrikaans aarde, earth, plus vark, pig, is an earth pig. It starts with a double a, spelled A, A, R, D.","show":{"t":"word","word":"aardvark","hi":[0,2]}},{"mood":"excited","cap":"Ask origin, definition, and a sentence.","say":"So when no Latin or Greek fits, ask for the origin, the definition, and a sentence. Together those clues reveal the pattern, and rare words click into place.","show":{"t":"glyph","text":"3 clues","sub":"crack the word"}}]}};
